-- FIX-2: add Russian translations (scenario_ru + options[].text_ru) to all
-- servable questions. Built from agent translations spliced onto PROD options
-- BY OPTION KEY (case-insensitive) — option text_en/text_az/correct_answer
-- semantics are preserved; only text_ru is added. Idempotent: re-run sets
-- the same values. Source: scripts/fix2_build_ru_migration.py.

UPDATE public.questions SET
    scenario_ru = 'Вы руководитель команды. В ходе подготовки мероприятия вы обнаруживаете, что на именных бейджах допущена опечатка — 30 имён написаны с ошибками. До начала события остаётся 90 минут, и организатор пока этого не заметил. Что вы сделаете В ПЕРВУЮ ОЧЕРЕДЬ?',
    options = '[{"key": "A", "text_az": "Təşkilatçının özünün fərqinə varıb-varmayacağını gözləyin.", "text_en": "Wait to see if the organizer notices on their own", "text_ru": "Подождать и посмотреть, заметит ли организатор ошибку самостоятельно"}, {"key": "B", "text_az": "Dərhal təşkilatçını dəqiq problem və onu həll etmək üçün qalan vaxt haqqında məlumatlandırın.", "text_en": "Immediately inform the organizer with the exact problem and the time remaining to fix it", "text_ru": "Немедленно сообщить организатору о точном характере проблемы и времени, оставшемся на её устранение"}, {"key": "C", "text_az": "Nişanları özünüz heç kimə xəbər vermədən düzəltməyə çalışın.", "text_en": "Try to fix the badges yourself without telling anyone", "text_ru": "Постараться исправить бейджи самостоятельно, никому об этом не говоря"}, {"key": "D", "text_az": "Həmkarlarınıza deyin, amma təşkilatçıya deməyin — bu, onları utandıra bilər.", "text_en": "Tell your colleagues but not the organizer — it might embarrass them", "text_ru": "Сообщить коллегам, но не организатору — это может его смутить"}]'::jsonb
WHERE id = 'c0000001-0000-0000-0000-000000000006';

UPDATE public.questions SET
    scenario_ru = 'Вам нужно отправить WhatsApp-сообщение 45 сотрудникам с информацией о том, что завтрашний брифинг, запланированный на 08:00, перенесён на 09:30 в аудиторию C-7. Какой из вариантов НАИЛУЧШИЙ?',
    options = '[{"key": "A", "text_az": "Nəzərinizə çatdırırıq ki, səhər brifinqinin cədvəlində kiçik bir dəyişiklik edilmişdir. Brifinq əvvəlcədən planlaşdırıldığından bir qədər gec keçiriləcəkdir.", "text_en": "Hey team, just so you know, there has been a slight change to the morning briefing schedule, it is now going to be a little later than originally planned", "text_ru": "Команда, обратите внимание: в расписании утреннего брифинга произошли небольшие изменения, теперь он начнётся немного позже запланированного"}, {"key": "B", "text_az": "Yeniləmə: Sabahkı brifinq C-7 otağında artıq saat 09:30-da keçiriləcəkdir (əvvəl saat 08:00-da idi). Xahiş edirik, qəbulu 👍 işarəsi ilə təsdiqləyin.", "text_en": "UPDATE: Tomorrow briefing is NOW 09:30 in Room C-7 (was 08:00). Please confirm receipt with a thumbs-up.", "text_ru": "ОБНОВЛЕНИЕ: завтрашний брифинг теперь в 09:30, аудитория C-7 (вместо 08:00). Пожалуйста, подтвердите получение сообщения — 👍."}, {"key": "C", "text_az": "Dəyişdirilib. C7 930.", "text_en": "Changed. C7 930.", "text_ru": "Перенос. C7 930."}, {"key": "D", "text_az": "Nəzərinizə çatdırılır ki, bəzi logistik məsələlər səbəbindən, saat 08:00-a ilkin olaraq planlaşdırılan brifinq C-7 otağında saat 09:30-a keçirilmişdir.", "text_en": "Please note that due to some logistical considerations, the briefing originally scheduled for 08:00 has been rescheduled to 09:30 in Room C-7.", "text_ru": "Сообщаем, что в связи с рядом организационных обстоятельств брифинг, первоначально запланированный на 08:00, перенесён на 09:30 в аудиторию C-7."}]'::jsonb
WHERE id = 'c0000001-0000-0000-0000-000000000007';

UPDATE public.questions SET
    scenario_ru = 'Вы последовательно объясняете приложение для регистрации сотрудников двум разным группам: сначала студентам университета (21–25 лет), затем старшим членам сообщества (60+ лет). Как следует адаптировать подачу информации?',
    options = '[{"key": "A", "text_az": "Hər iki üçün tamamilə eyni izahat verilməlidir — vahidlik hər kəsin eyni məlumatı almasını təmin edir.", "text_en": "Use exactly the same explanation for both — consistency ensures everyone gets the same information", "text_ru": "Давать одинаковое объяснение обеим группам — единообразие гарантирует, что все получат одну и ту же информацию"}, {"key": "B", "text_az": "Tələbələrlə texniki proqram terminologiyasından istifadə edin; yaşlılar üçün isə tempinizi azaldın, fiziki nümayişlərdən istifadə edin və jarqondan çəkinin.", "text_en": "Use technical app terminology with students; for seniors, slow your pace, use physical demos, and avoid jargon", "text_ru": "Со студентами использовать техническую терминологию приложения; для старшей группы замедлить темп, прибегнуть к наглядной демонстрации и избегать профессионального жаргона"}, {"key": "C", "text_az": "Yaşlılar üçün tətbiqin izahını keçin — onlar onsuz da yəqin ki, ondan istifadə etməyəcəklər.", "text_en": "Skip the app explanation for seniors — they probably won''t use it anyway", "text_ru": "Пропустить объяснение приложения для старшей группы — они всё равно, скорее всего, им не воспользуются"}, {"key": "D", "text_az": "Əvəzinə, daha gənc bir komanda üzvüyə yaşlılara bunu izah etməyi tapşırın.", "text_en": "Ask a younger team member to explain it to the seniors instead", "text_ru": "Попросить кого-то из молодых коллег объяснить приложение старшей группе вместо вас"}]'::jsonb
WHERE id = 'c0000001-0000-0000-0000-000000000008';

UPDATE public.questions SET
    scenario_ru = 'В разгар мероприятия к вам подходит расстроенный участник: он говорит быстро, на глазах слёзы. Он произносит: «Меня никто не слушает, я не знаю, что делать.» До вашего следующего задания остаётся 3 минуты. Какой ответ будет НАИБОЛЕЕ эффективным с точки зрения коммуникации?',
    options = '[{"key": "A", "text_az": "Onları dərhal dəstək masasına yönləndirin — siz bunun üçün təlim keçməmisiniz.", "text_en": "Immediately redirect them to the help desk — you are not trained for this", "text_ru": "Немедленно направить его за помощью на стойку поддержки — вы не проходили соответствующей подготовки"}, {"key": "B", "text_az": "Durun, onlarla birbaşa üzbəüz olun, qısa göz təması qurun, \"Mən sizi eşidirəm\" deyin, sonra növbəti addımlara qərar verməzdən əvvəl əsas məsələni anlamaq üçün bir diqqət mərkəzli sual verin.", "text_en": "Stop, face them directly, make brief eye contact, say I hear you — then ask one focused question to understand the core issue before deciding next steps", "text_ru": "Остановиться, повернуться к человеку лицом, установить краткий зрительный контакт, сказать «Я вас слышу» — затем задать один конкретный вопрос, чтобы понять суть проблемы, прежде чем принимать дальнейшие решения"}, {"key": "C", "text_az": "Saatınıza nəzər salaraq 30 saniyə dinləyin ki, vaxtınızın məhdud olduğunu bilsinlər.", "text_en": "Listen for 30 seconds while glancing at your watch so they know you have limited time", "text_ru": "Слушать 30 секунд, время от времени поглядывая на часы, чтобы человек понял: ваше время ограничено"}, {"key": "D", "text_az": "Onların nəzərdə tutduqlarını düşündüyünüzə əsaslanaraq, vəziyyətlərini özlərinə ümumiləşdirin, sonra onlara məsləhət verin.", "text_en": "Summarize their situation back to them based on what you think they mean, then give them advice", "text_ru": "На основе собственного понимания изложить ситуацию участника своими словами, а затем дать ему совет"}]'::jsonb
WHERE id = 'c0000001-0000-0000-0000-000000000009';

UPDATE public.questions SET
    scenario_ru = 'Вы предлагаете команде новый подход к координации работы. Трое из пяти коллег открыто возражают, говоря, что прежняя система прекрасно работает. Полномочий принудительно внедрить изменение у вас нет. Какая коммуникационная стратегия будет НАИБОЛЕЕ эффективной для получения поддержки?',
    options = '[{"key": "A", "text_az": "Təklifinizi daha aydın və daha ətraflı təkrarlayın, ehtimal ki, ilk dəfə onu başa düşmədilər.", "text_en": "Repeat your proposal more clearly and with more detail — they probably didn''t understand it the first time", "text_ru": "Повторить своё предложение чётче и с бо́льшим количеством деталей — возможно, в первый раз они просто не поняли"}, {"key": "B", "text_az": "Hər bir etirazçıdan soruşun: Sizin onu dəstəkləməyiniz üçün cari təkliflə bağlı hansı konkret məsələnin dəyişdirilməsi zəruridir? Və sonra həmin məsələləri birbaşa həll edin.", "text_en": "Ask each dissenter: What specific concern about the current proposal would need to change for you to support it? — then address those concerns directly", "text_ru": "Спросить у каждого несогласного: «Что именно в текущем предложении нужно изменить, чтобы вы его поддержали?» — и затем напрямую разобраться с этими замечаниями"}, {"key": "C", "text_az": "Ən nüfuzlu komanda üzvünü tapın və onu fərdi şəkildə inandırın — digərləri də izləyəcək.", "text_en": "Find the most influential teammate and convince them privately — the others will follow", "text_ru": "Найти наиболее авторитетного коллегу и убедить его в приватном разговоре — остальные последуют его примеру"}, {"key": "D", "text_az": "Hələlik təklifi geri çəkməyə və daha çox səlahiyyətiniz olduqda onu yenidən gündəmə gətirməyə razılıq vermək.", "text_en": "Agree to drop the proposal for now and bring it back when you have more authority", "text_ru": "Согласиться отозвать предложение сейчас и вернуться к нему, когда у вас будет больше полномочий"}]'::jsonb
WHERE id = 'c0000001-0000-0000-0000-000000000010';

UPDATE public.questions SET
    scenario_ru = 'Коллега сдаёт клиентский отчёт с несколькими ошибками форматирования и двумя фактическими неточностями. Дедлайн завтра, а руководитель ожидает безупречный документ. Как ЛУЧШЕ всего сообщить об этом коллеге?',
    options = '[{"key": "A", "text_az": "Onlara demədən səhvləri özün düzəlt — daha sürətlidir", "text_en": "Fix the errors yourself without telling them — it is faster", "text_ru": "Исправить ошибки самостоятельно, ничего не говоря коллеге — так быстрее"}, {"key": "B", "text_az": "Onlara konkret xətaları vurğulayan, müştəriyə təsirini izah edən və düzəldilmiş versiyanı birlikdə nəzərdən keçirməyi təklif edən mesaj göndərin", "text_en": "Send them a message highlighting the specific errors, explaining the impact on the client, and offering to review the corrected version together", "text_ru": "Написать коллеге сообщение с указанием конкретных ошибок, объяснив их возможные последствия для клиента, и предложить вместе проверить исправленную версию"}, {"key": "C", "text_az": "Birbaşa həll etməsi üçün menecerinizə eskalasiya edin", "text_en": "Escalate to your manager so they can address it directly", "text_ru": "Эскалировать ситуацию руководителю, чтобы он разобрался напрямую"}, {"key": "D", "text_az": "Qeyd etmək üçün son tarixdən sonranı gözləyin — indi onları stresə salmağın mənası yoxdur", "text_en": "Wait until after the deadline to mention it — no point stressing them now", "text_ru": "Подождать с замечаниями до истечения дедлайна — нет смысла добавлять лишний стресс прямо сейчас"}]'::jsonb
WHERE id = 'c0000001-0000-0000-0000-000000000011';

UPDATE public.questions SET
    scenario_ru = 'После межотдельского совещания продолжительностью 90 минут с 12 участниками директор просит вас в течение часа разослать всем присутствовавшим итоговое письмо. На встрече обсуждалось пять тем, однако решения были приняты лишь по двум из них. На чём должно быть сосредоточено письмо?',
    options = '[{"key": "A", "text_az": "İclas zamanı kimin nə dediyinin xronoloji əlyazması", "text_en": "A chronological transcript of who said what during the meeting", "text_ru": "Хронологическая запись того, кто что говорил в ходе совещания"}, {"key": "B", "text_az": "Qəbul edilmiş iki qərar, sahibləri və son tarixləri olan hərəkət bəndləri, və üç açıq mövzu haqqında qısa qeyd", "text_en": "The two decisions made, action items with owners and deadlines, and a brief note on the three open topics", "text_ru": "Два принятых решения, пункты плана действий с указанием ответственных и сроков, а также краткое упоминание трёх открытых вопросов"}, {"key": "C", "text_az": "Yalnız iki qərar — açıq mövzuları hələlik qeyd etməyə dəyməz", "text_en": "Only the two decisions — the open topics are not worth mentioning yet", "text_ru": "Только два принятых решения — открытые вопросы пока не стоит упоминать"}, {"key": "D", "text_az": "Hər birinə bərabər yer verilməklə beş mövzunun ətraflı xülasəsi", "text_en": "A detailed summary of all five topics with equal space given to each", "text_ru": "Подробное резюме по всем пяти темам с равным вниманием к каждой"}]'::jsonb
WHERE id = 'c0000001-0000-0000-0000-000000000012';

UPDATE public.questions SET
    scenario_ru = 'Менеджер проекта присылает вам сообщение: «Пожалуйста, подготовьте данные для ежеквартального обзора.» Вы не уверены, какой именно набор данных, формат и сроки он имеет в виду. Какой будет НАИЛУЧШИЙ следующий шаг?',
    options = '[{"key": "A", "text_az": "Keçən rübün formatına əsasən nə nəzərdə tutduqlarını düşündüyünüzü hazırlayın — səhv olarsa düzəldəcəklər", "text_en": "Prepare what you think they mean based on last quarter''s format — they will correct you if it is wrong", "text_ru": "Подготовить то, что, на ваш взгляд, имеется в виду, ориентируясь на формат прошлого квартала — если что-то не так, вас поправят"}, {"key": "B", "text_az": "Konkret aydınlaşdırma ilə cavab verin: ''Təsdiq üçün — cümə saat 15:00-a qədər slayd şablonunda Q1 satış məlumat dəstini lazımdır. Doğrudurmu?''", "text_en": "Reply with a specific clarification: ''To confirm — you need the Q1 sales dataset in the slide template by Friday 3pm. Is that correct?''", "text_ru": "Ответить с конкретным уточнением: «Для подтверждения — нужен набор данных по продажам за Q1 в шаблоне презентации к пятнице до 15:00. Верно?»"}, {"key": "C", "text_az": "Menecerin nə nəzərdə tutduğunu düşündüklərini həmkarınızdan soruşun", "text_en": "Ask a colleague what they think the manager meant", "text_ru": "Спросить у коллеги, что, по его мнению, имел в виду менеджер"}, {"key": "D", "text_az": "Menecerin daha ətraflı məlumat göndərməsini gözləyin — təcili olarsa əlavə edəcəklər", "text_en": "Wait for the manager to send more details — they will follow up if it is urgent", "text_ru": "Подождать, пока менеджер пришлёт дополнительную информацию — если это срочно, он сам напомнит"}]'::jsonb
WHERE id = 'c0000001-0000-0000-0000-000000000013';

UPDATE public.questions SET
    scenario_ru = 'Вы руководите проектной командой, в которую входят участники из четырёх стран. Во время видеоконференции вы замечаете, что двое представителей культур высокого контекста никогда не высказывают несогласие открыто, тогда как двое из культур низкого контекста доминируют в обсуждении. Проект требует честного вклада от каждого. Какой подход будет НАИБОЛЕЕ эффективным?',
    options = '[{"key": "A", "text_az": "Hər kəsə bərabər davranın — zəng zamanı hər kəsə eyni sualı eyni şəkildə verin", "text_en": "Treat everyone equally — ask each person the same question in the same way during the call", "text_ru": "Обращаться со всеми одинаково — задавать каждому одни и те же вопросы одинаковым образом во время звонка"}, {"key": "B", "text_az": "Zəngdən əvvəl anonim sorğu göndərin. Zəng zamanı növbəli danışıq istifadə edin. Zəngdən sonra şəxsi paylaşa biləcəkləri fikirləri almaq üçün sakit üzvlərlə fərdi əlaqə qurun", "text_en": "Before the call, send an anonymous survey. During the call, use round-robin turns. After the call, follow up individually with quiet members to capture insights they may share privately", "text_ru": "До звонка провести анонимный опрос. Во время звонка применять поочерёдный порядок высказываний. После звонка связаться индивидуально с молчаливыми участниками, чтобы получить мнения, которые они могут не решаться высказывать публично"}, {"key": "C", "text_az": "Sakit üzvlərə daha çox danışmalı olduqlarını söyləyin — birbaşalıq peşəkar gözləntidir", "text_en": "Tell the quiet members they need to speak up more — directness is a professional expectation", "text_ru": "Сказать молчаливым участникам, что им нужно высказываться активнее — прямота является профессиональным стандартом"}, {"key": "D", "text_az": "Dominant üzvlərə rəhbərlik etməyə icazə verin çünki daha fəaldırlar — sakit olanlar sonra e-poçt vasitəsilə töhfə verə bilərlər", "text_en": "Let the dominant members lead since they are more engaged — the quiet ones can contribute via email later", "text_ru": "Позволить доминирующим участникам взять на себя инициативу, поскольку они более активны, — молчаливые смогут поделиться своим мнением по электронной почте позже"}]'::jsonb
WHERE id = 'c0000001-0000-0000-0000-000000000014';

UPDATE public.questions SET
    scenario_ru = 'До презентации продукта вашей команды ключевому клиенту остаётся 2 часа. Основной докладчик только что сообщил о болезни, а его заместитель ни разу не видел последнюю версию слайд-деков. Вы координатор проекта. Какие коммуникационные шаги вы предпримете В ПЕРВУЮ ОЧЕРЕДЬ?',
    options = '[{"key": "A", "text_az": "Təxirə salmaq üçün müştəriyə e-poçt göndərin — pis təqdimatdan gec etmək yaxşıdır", "text_en": "Email the client to postpone — better to delay than to present poorly", "text_ru": "Написать клиенту письмо с просьбой перенести встречу — лучше отложить, чем провести презентацию на низком уровне"}, {"key": "B", "text_az": "Ehtiyat təqdimçini 3 kritik slayd haqqında məlumatlandırın, digər komanda üzvlərinə ən yaxşı bildikləri S&C bölmələrini həvalə edin, və müştəriyə təqdimat komandasının dəyişdiyini bildirin", "text_en": "Brief the backup presenter on the 3 critical slides, assign other team members to handle Q&A sections they know best, and notify the client that the presenting team has changed", "text_ru": "Ввести заместителя в курс по 3 ключевым слайдам, поручить другим членам команды те блоки вопросов и ответов, которые они знают лучше всего, и уведомить клиента о смене состава докладчиков"}, {"key": "C", "text_az": "Təqdimatı özünüz edin — koordinator kimi layihəni ən yaxşı siz tanıyırsınız", "text_en": "Do the presentation yourself — you know the project best as coordinator", "text_ru": "Провести презентацию самостоятельно — как координатор вы знаете проект лучше всех"}, {"key": "D", "text_az": "Slayd destini ehtiyat təqdimçiyə göndərin və öz başına hazırlanacağına etibar edin", "text_en": "Send the slide deck to the backup presenter and trust them to prepare on their own", "text_ru": "Выслать слайд-дек заместителю и рассчитывать на то, что он подготовится самостоятельно"}]'::jsonb
WHERE id = 'c0000001-0000-0000-0000-000000000015';

UPDATE public.questions SET
    scenario_ru = 'Вы представляете новый инструмент для управления рабочими процессами 20 руководителям подразделений, которые открыто заявили, что их устраивает текущая система. В вашем распоряжении 15 минут. Какая коммуникационная структура будет НАИБОЛЕЕ убедительной?',
    options = '[{"key": "A", "text_az": "Yeni alətin nə etdiyini görə bilmələri üçün tam xüsusiyyət icmalı ilə başlayın", "text_en": "Start with a full feature walkthrough so they can see everything the new tool does", "text_ru": "Начать с полного обзора функций, чтобы аудитория могла увидеть всё, что умеет новый инструмент"}, {"key": "B", "text_az": "Mövcud sistemin işlədiyini etiraf edərək başlayın, sonra yeni alətin onların öz şöbəsindən məlumatlarla həll etdiyi 2-3 konkret problem nöqtəsini təqdim edin və aşağı riskli pilot təklifi ilə bitirin", "text_en": "Begin by acknowledging the current system works, then present 2-3 specific pain points the new tool solves with data from their own department, and end with a low-risk pilot proposal", "text_ru": "Начать с признания того, что текущая система работает, затем представить 2–3 конкретные проблемы, которые решает новый инструмент, — используя данные из их собственных подразделений, — и завершить предложением о пилотном запуске с минимальными рисками"}, {"key": "C", "text_az": "Keçid edən digər şirkətlərdən rəylər göstərin — sosial sübut qəbulu sürətləndirir", "text_en": "Show testimonials from other companies that switched — social proof drives adoption", "text_ru": "Показать отзывы других компаний, перешедших на новый инструмент, — социальное доказательство ускоряет принятие изменений"}, {"key": "D", "text_az": "Xərclərə qənaətə diqqət yetirin — menecerlər maliyyə arqumentlərinə ən yaxşı cavab verir", "text_en": "Focus on cost savings — managers respond best to financial arguments", "text_ru": "Сделать акцент на экономии затрат — руководители лучше всего реагируют на финансовые аргументы"}]'::jsonb
WHERE id = 'c0000001-0000-0000-0000-000000000016';

UPDATE public.questions SET
    scenario_ru = 'Один из членов команды пропустил три дедлайна подряд. Качество его работы превосходное, когда она наконец сдаётся, однако задержки сказываются на всём графике проекта. Вам необходимо поговорить с ним. Какой подход к коммуникации будет НАИБОЛЕЕ эффективным?',
    options = '[{"key": "A", "text_az": "Buraxılmış son tarixləri sənədləşdirən e-poçt göndərin və hesabatlılıq üçün menecerinə cc edin", "text_en": "Send them an email documenting the missed deadlines and cc their manager for accountability", "text_ru": "Отправить письмо с перечислением пропущенных дедлайнов и поставить в копию его руководителя для обеспечения ответственности"}, {"key": "B", "text_az": "Şəxsi üzbəüz söhbət edin: işlərinin keyfiyyətini etiraf edin, gecikmələrin komandaya konkret təsirini bildirin, hansı maneələrlə üzləşdiklərini soruşun, və birlikdə real cədvəl yaradın", "text_en": "Have a private face-to-face conversation: acknowledge their quality of work, state the specific impact of the delays on the team, ask what barriers they are facing, and co-create a realistic timeline together", "text_ru": "Провести личную беседу с глазу на глаз: отметить высокое качество работы, конкретно обозначить влияние задержек на команду, спросить, с какими препятствиями он сталкивается, и совместно выработать реалистичный график"}, {"key": "C", "text_az": "Tapşırıqlarını daha sürətli birinə həvalə edin — hərəkətlər sözlərdən daha güclüdür", "text_en": "Reassign their tasks to someone faster — actions speak louder than words", "text_ru": "Перераспределить его задачи в пользу более расторопного сотрудника — действия говорят громче слов"}, {"key": "D", "text_az": "Söhbət etmədən onlara bir şans daha verin — bəlkə şəxsi bir şey yaşayırlar", "text_en": "Give them one more chance without a conversation — maybe they are going through something personal", "text_ru": "Дать ещё один шанс, не вступая в разговор — возможно, у него сейчас трудные личные обстоятельства"}]'::jsonb
WHERE id = 'c0000001-0000-0000-0000-000000000017';

UPDATE public.questions SET
    scenario_ru = 'Двое старших специалистов вашей проектной команды публично расходятся во мнениях в ходе воркшопа с клиентом. Один настаивает на подходе A, другой — на подходе B. Оба приводят весомые технические аргументы. Клиент явно чувствует дискомфорт, а до конца воркшопа остаётся 45 минут. Что вы, как руководитель проекта, предпримете?',
    options = '[{"key": "A", "text_az": "Debat etmələrinə icazə verin — ən yaxşı arqument qalib gələcək və müştəri ciddi komanda görəcək", "text_en": "Let them debate — the best argument will win and the client sees a rigorous team", "text_ru": "Позволить им дискутировать — победит сильнейший аргумент, а клиент увидит, что команда подходит к делу основательно"}, {"key": "B", "text_az": "Hər iki mövqeyi ictimai olaraq etiraf edin, debatı ''A seçimi X üçün optimallaşdırır, B seçimi Y üçün — hər ikisini müştərinin prioritetlərinə uyğunlaşdıraq'' kimi yenidən çərçivələyin, sonra müştərinin giriş ilə strukturlaşdırılmış müqayisə aparın", "text_en": "Acknowledge both positions publicly, reframe the debate as ''Option A optimizes for X, Option B for Y — let us map both against the client''s priorities,'' then facilitate a structured comparison with the client''s input", "text_ru": "Публично признать обе точки зрения, переосмыслить дискуссию в формате «Вариант A оптимален для X, вариант B — для Y; давайте соотнесём оба с приоритетами клиента» и провести структурированное сравнение с учётом мнения клиента"}, {"key": "C", "text_az": "Fikir ayrılığını tez bitirmək üçün daha təcrübəli mütəxəssisin tərəfini tutun", "text_en": "Side with the more experienced specialist to end the disagreement quickly", "text_ru": "Поддержать более опытного специалиста, чтобы быстро прекратить разногласие"}, {"key": "D", "text_az": "Fasilə elan edin və hər iki mütəxəssisdən davam etməzdən əvvəl bunu şəxsi olaraq həll etmələrini xahiş edin", "text_en": "Call for a break and ask both specialists to resolve it privately before resuming", "text_ru": "Объявить перерыв и попросить обоих специалистов урегулировать разногласие в приватном порядке до продолжения воркшопа"}]'::jsonb
WHERE id = 'c0000001-0000-0000-0000-000000000018';

UPDATE public.questions SET
    scenario_ru = 'Высшее руководство приняло решение закрыть проект, над которым ваша команда из 8 человек работала 3 месяца. Решение окончательное и пересмотру не подлежит. Вы должны сообщить об этом на завтрашнем командном совещании. Двое участников уже дали понять, что будут расстроены. Какая коммуникационная стратегия будет НАИБОЛЕЕ эффективной?',
    options = '[{"key": "A", "text_az": "Qərarı iclasdan əvvəl e-poçtla paylaşın ki, insanlar onu şəxsi olaraq həzm etsinlər, sonra iclası suallar üçün istifadə edin", "text_en": "Share the decision via email before the meeting so people can process it privately, then use the meeting for questions", "text_ru": "Разослать решение по электронной почте до совещания, чтобы люди могли осмыслить его наедине с собой, а само совещание использовать для ответов на вопросы"}, {"key": "B", "text_az": "İclasda qərarı biznes əsaslandırması ilə aydın bildirin, komandanın səyini və emosional təsirini etiraf edin, reaksiyalara yer verin, sonra diqqəti onların bacarıqlarının bundan sonra necə istifadə olunacağına yönləndirin", "text_en": "In the meeting, state the decision clearly with the business reasoning, acknowledge the team''s effort and the emotional impact, allow space for reactions, and then redirect focus to how their skills will be deployed next", "text_ru": "На совещании чётко объявить о решении с деловым обоснованием, признать вклад команды и эмоциональное воздействие происходящего, дать пространство для реакции, а затем переключить внимание на то, где найдут применение их навыки в дальнейшем"}, {"key": "C", "text_az": "Zərbəni yumşaltmaq üçün onu ləğvetmə deyil, ''pauza'' kimi çərçivələyin — sonra həmişə davam edə bilərlər", "text_en": "Soften the blow by framing it as a ''pause'' rather than a cancellation — they can always resume later", "text_ru": "Смягчить удар, представив закрытие проекта как «паузу», а не окончательное решение — впоследствии работу всегда можно будет возобновить"}, {"key": "D", "text_az": "Mesajı tez çatdırın və yeni tapşırıqlara keçin — üzərində dayanmaq yalnız vəziyyəti pisləşdirəcək", "text_en": "Deliver the message quickly and move on to new assignments — dwelling on it will only make it worse", "text_ru": "Быстро сообщить новость и перейти к новым задачам — чем дольше на этом задерживаться, тем хуже"}]'::jsonb
WHERE id = 'c0000001-0000-0000-0000-000000000019';

UPDATE public.questions SET
    scenario_ru = 'Вы готовите брифинг для генерального директора. Три подразделения представили данные по одному и тому же решению: маркетинг рекомендует выпуск сейчас (исходя из действий конкурентов), финансовый департамент — отложить на 6 месяцев (исходя из денежного потока), инженерный отдел сообщает, что выпуск технически осуществим, однако качество составляет 85%. Генеральный директор ожидает от вас рекомендацию на одну страницу. Какой подход к коммуникации НАИЛУЧШИЙ?',
    options = '[{"key": "A", "text_az": "Üç perspektivi bərabər təqdim edin və Baş direktorun qərara gəlməsinə icazə verin — tövsiyə etmək sizin yeriniz deyil", "text_en": "Present the three perspectives equally and let the CEO decide — it is not your place to recommend", "text_ru": "Представить все три точки зрения в равной мере и дать генеральному директору самому принять решение — давать рекомендации не ваша роль"}, {"key": "B", "text_az": "Əsas əsaslandırma ilə tövsiyənizi əvvəlcə bildirin, sonra üç girişi dəstəkləyici/ziddiyyətli sübut kimi təqdim edin, əsas kompromisi açıq adlandırın, və tövsiyə olunan yol üçün risk və azaltmanı daxil edin", "text_en": "State your recommendation first with the primary rationale, then present the three inputs as supporting/conflicting evidence, name the key trade-off explicitly, and include the risk and mitigation for the recommended path", "text_ru": "Сначала изложить свою рекомендацию с ключевым обоснованием, затем представить данные трёх подразделений как подтверждающие или противоречащие доказательства, прямо обозначить ключевой компромисс и включить оценку рисков и меры их снижения для предлагаемого пути"}, {"key": "C", "text_az": "Maliyyənin tərəfini tutun — maliyyə ehtiyatlılığı icra səviyyəsində həmişə qalib gəlir", "text_en": "Side with Finance — financial prudence always wins at the executive level", "text_ru": "Поддержать позицию финансового департамента — финансовая осмотрительность неизменно берёт верх на уровне топ-менеджмента"}, {"key": "D", "text_az": "Kompromis təqdim edin: hər üç şöbəni razı salmaq üçün indi məhdud versiya buraxın", "text_en": "Present a compromise: launch a limited version now to satisfy all three departments", "text_ru": "Предложить компромисс: выпустить ограниченную версию прямо сейчас, чтобы удовлетворить все три подразделения"}]'::jsonb
WHERE id = 'c0000001-0000-0000-0000-000000000020';

UPDATE public.questions SET
    scenario_ru = 'Вы записались на работу за стойкой регистрации культурного фестиваля с 8:00 до 14:00. В утро мероприятия вы просыпаетесь немного усталым, но не больным. Что вы делаете?',
    options = '[{"key": "A", "text_az": "Koordinatora zəng edin və gələ bilməyəcəyinizi bildirin.", "text_en": "Call the coordinator and say you cannot make it", "text_ru": "Позвоните координатору и сообщите, что не сможете прийти."}, {"key": "B", "text_az": "Razılaşdırıldığı kimi vaxtında gəlin və növbənizi yerinə yetirin.", "text_en": "Show up on time as committed and fulfill your shift", "text_ru": "Придите вовремя, как и договаривались, и отработайте свою смену."}, {"key": "C", "text_az": "Heç kəsin fərqinə varmayacağına ümid edərək bir saat gec gəlmək.", "text_en": "Arrive an hour late hoping no one notices", "text_ru": "Опоздайте на час, надеясь, что никто не заметит."}, {"key": "D", "text_az": "Koordinatora məlumat vermədən bir dostdan sizi əvəz etməsini xahiş edin.", "text_en": "Ask a friend to cover without informing the coordinator", "text_ru": "Попросите друга вас подменить, не поставив координатора в известность."}]'::jsonb
WHERE id = '20000001-0000-0000-0000-000000000001';

UPDATE public.questions SET
    scenario_ru = 'Руководитель команды попросил вас сдать анкету о доступности до пятницы. Сейчас вечер четверга, а анкета так и не заполнена. Какое действие наиболее ответственно?',
    options = '[{"key": "A", "text_az": "Onu dərhal doldurun və bu gecə təqdim edin.", "text_en": "Fill it out immediately and submit tonight", "text_ru": "Заполните её немедленно и сдайте сегодня вечером."}, {"key": "B", "text_az": "Hələ vaxt olduğu üçün Cümə səhərinə qədər gözləyin.", "text_en": "Wait until Friday morning since there is still time", "text_ru": "Подождите до утра пятницы — время ещё есть."}, {"key": "C", "text_az": "Onu görməzlikdən gəlin, komanda rəhbəri sizə xatırladacaq.", "text_en": "Ignore it — the team lead will remind you", "text_ru": "Проигнорируйте — руководитель команды сам вам напомнит."}, {"key": "D", "text_az": "Sizin adınızdan təqdim etməyi bir komanda üzvünə tapşırın.", "text_en": "Ask a teammate to submit on your behalf", "text_ru": "Попросите коллегу сдать анкету от вашего имени."}]'::jsonb
WHERE id = '20000001-0000-0000-0000-000000000002';

UPDATE public.questions SET
    scenario_ru = 'Опишите ситуацию, когда вы взяли на себя обязательство что-то сделать, а затем столкнулись с препятствием и должны были решить: выполнять его дальше или нет. Что вы сделали и почему?'
WHERE id = '20000001-0000-0000-0000-000000000003';

UPDATE public.questions SET
    scenario_ru = 'Вы координируете работу 8 членов команды на международном спортивном мероприятии. За 90 минут до начала смены двое из них сообщают вам в сообщении, что не смогут прийти. Списка замен у вас нет. Каков ваш первый шаг?',
    options = '[{"key": "A", "text_az": "Dərhal rəhbərinizə məlumat verin və tapşırıqları qalan 6 nəfər arasında yenidən bölüşdürməyi təklif edin.", "text_en": "Inform your supervisor immediately and propose redistributing tasks among the remaining 6", "text_ru": "Немедленно сообщите руководителю и предложите перераспределить задачи между оставшимися 6 участниками."}, {"key": "B", "text_az": "Onların fikirlərini dəyişib-dəyişmədiklərini görməyi gözləyin.", "text_en": "Wait to see if they change their minds", "text_ru": "Подождите, вдруг они передумают."}, {"key": "C", "text_az": "Hər şeyi özünüz həll edin.", "text_en": "Handle everything yourself", "text_ru": "Справьтесь со всем самостоятельно."}, {"key": "D", "text_az": "Sosial mediada komanda üzvülər çağırışı etmək.", "text_en": "Post on social media asking for team members", "text_ru": "Разместите в социальных сетях объявление с просьбой о помощи."}]'::jsonb
WHERE id = '20000001-0000-0000-0000-000000000004';

UPDATE public.questions SET
    scenario_ru = 'Вы пообещали сдать переведённый приветственный пакет к понедельнику. В воскресенье вечером вы заканчиваете работу и замечаете ошибки в одном из разделов. На исправление потребуется ещё 2 часа. Что вы делаете?',
    options = '[{"key": "A", "text_az": "Son tarixə çatdırmaq üçün onu olduğu kimi təqdim edin.", "text_en": "Submit it as-is to meet the deadline", "text_ru": "Сдайте материал в текущем виде, чтобы уложиться в срок."}, {"key": "B", "text_az": "Aktiv olun və səhvləri vaxtında düzəldin.", "text_en": "Stay up and fix the errors on time", "text_ru": "Не ложитесь спать и исправьте ошибки вовремя."}, {"key": "C", "text_az": "Koordinatorunuza bu axşam bildirin və dəyişdirilmiş son tarix təklif edin.", "text_en": "Notify your coordinator tonight and propose a revised deadline", "text_ru": "Сообщите координатору этим вечером и предложите скорректированный дедлайн."}, {"key": "D", "text_az": "Düzəlişi keçin — nümayəndələr onları nadir hallarda diqqətlə oxuyurlar.", "text_en": "Skip the correction — delegates rarely read them carefully", "text_ru": "Пропустите исправление — делегаты всё равно редко читают подобные материалы внимательно."}]'::jsonb
WHERE id = '20000001-0000-0000-0000-000000000005';

UPDATE public.questions SET
    scenario_ru = 'Вы ведёте задачу с дедлайном в рамках многодневного мероприятия. На полпути вы понимаете, что не успеете завершить её вовремя. Опишите, как именно вы будете действовать в этой ситуации.'
WHERE id = '20000001-0000-0000-0000-000000000006';

UPDATE public.questions SET
    scenario_ru = 'Руководитель поручает вам задачу без конкретного срока, говоря: «Сделайте, когда сможете». Проходит три дня. Что вы делаете?',
    options = '[{"key": "A", "text_az": "Kimsə bu barədə soruşana qədər gözləyin.", "text_en": "Wait until someone asks about it", "text_ru": "Ждёте, пока кто-нибудь не спросит об этом."}, {"key": "B", "text_az": "Öz daxili son tarixinizi təyin edin, tapşırığı tamamlayın və rəhbərinizi qabaqlayıcı olaraq məlumatlandırın.", "text_en": "Set your own internal deadline, complete the task, and proactively update your supervisor", "text_ru": "Устанавливаете собственный внутренний дедлайн, выполняете задачу и по собственной инициативе информируете руководителя."}, {"key": "C", "text_az": "Başlamazdan əvvəl rəhbərinizdən son tarixi soruşun.", "text_en": "Ask your supervisor for a deadline before starting", "text_ru": "Прежде чем приступить, просите руководителя назначить срок."}, {"key": "D", "text_az": "Hissəvi versiya hazırlayın və onu tamamlanmış kimi bildirin.", "text_en": "Do a partial version and report it as complete", "text_ru": "Делаете частичный вариант и отчитываетесь о нём как о выполненном."}]'::jsonb
WHERE id = '20000001-0000-0000-0000-000000000007';

UPDATE public.questions SET
    scenario_ru = 'На протяжении 6 месяцев вы неизменно были надёжным сотрудником. Теперь координатор, рассчитывая на вас, поручает вам значительно больше задач, чем другим. Вы приближаетесь к выгоранию. Какой ответ будет наиболее профессиональным и ответственным?',
    options = '[{"key": "A", "text_az": "Nüfuzunuzu qorumaq üçün bütün tapşırıqları səssizcə qəbul edin.", "text_en": "Accept all tasks silently to protect your reputation", "text_ru": "Молча принимайте все задачи, чтобы не потерять репутацию."}, {"key": "B", "text_az": "Qəfil hər şeydən imtina edin.", "text_en": "Decline everything suddenly", "text_ru": "Резко откажитесь от всего сразу."}, {"key": "C", "text_az": "Tutum barədə dürüst bir söhbət aparın və davamlı iş yükü təklif edin.", "text_en": "Have an honest conversation about capacity and propose a sustainable workload", "text_ru": "Поговорите открыто о своих возможностях и предложите устойчивый объём нагрузки."}, {"key": "D", "text_az": "Müddətləri qaçırmağa başlayın ki, koordinator yükünüzü azaltsın.", "text_en": "Start missing deadlines so the coordinator reduces your load", "text_ru": "Начните срывать дедлайны, чтобы координатор снизил нагрузку."}]'::jsonb
WHERE id = '20000001-0000-0000-0000-000000000008';

UPDATE public.questions SET
