UPDATE public.questions SET
    scenario_ru = 'Вы руководите командой из 8 человек на культурном фестивале. Один участник опаздывает на 30 минут и выглядит немотивированным. Что вы предпримете в первую очередь?',
    options = '[{"key": "A", "text_az": "Onları komandanın qarşısında açıq şəkildə tənbeh edin.", "text_en": "Publicly reprimand them in front of the team", "text_ru": "Публично сделать ему выговор при всей команде"}, {"key": "B", "text_az": "Fərdi şəkildə təmas qurun, səbəbi aydınlaşdırın və zərurət yaranarsa, yenidən təyin edin.", "text_en": "Privately check in, understand the reason, and reassign if needed", "text_ru": "Поговорить с ним наедине, выяснить причину и при необходимости перераспределить задачи"}, {"key": "C", "text_az": "Vəziyyəti gözardı etmək və işlərin yaxşılaşacağına ümid etmək", "text_en": "Ignore the situation and hope they improve", "text_ru": "Проигнорировать ситуацию и надеяться, что всё само наладится"}, {"key": "D", "text_az": "Dərhal onları tədbir təşkilatçısına bildirin.", "text_en": "Immediately report them to the event organizer", "text_ru": "Немедленно сообщить о нём организаторам мероприятия"}]'::jsonb
WHERE id = '40000001-0000-0000-0000-000000000001';

UPDATE public.questions SET
    scenario_ru = 'Перед началом саммита ваша команда заметно нервничает и не уверена в своих ролях. Какой первый шаг будет наиболее эффективным?',
