UPDATE public.questions SET
    scenario_ru = 'Вы руководите 20 участниками команды, распределёнными по 4 зонам. Одновременно поступают сообщения: в зоне 1 — проблема с контролем толпы, в зоне 3 — участник не явился на смену, зона 4 опережает график и нуждается в дополнительных задачах. В вашем распоряжении 3 минуты. Какая расстановка приоритетов верна?',
    options = '[{"key": "A", "text_az": "Əvvəlcə Zona 4 (üstünlük təşkil edir, daha çox qəbul edə bilər), daha sonra Zona 3, daha sonra Zona 1.", "text_en": "Zone 4 first (ahead, can take more), then Zone 3, then Zone 1", "text_ru": "Сначала зона 4 (опережает график, может взять больше задач), затем зона 3, затем зона 1"}, {"key": "B", "text_az": "Öncə Zona 1 (təhlükəsizlik), Zona 4 artığı Zona 3-ə yönləndirilsin, Zona 4-ün özünü idarə etməsi təsdiqlənsin.", "text_en": "Zone 1 first (safety), redirect Zone 4 surplus to Zone 3, confirm Zone 4 self-manages", "text_ru": "Сначала зона 1 (безопасность), перенаправить резерв зоны 4 в зону 3, убедиться, что зона 4 справляется самостоятельно"}, {"key": "C", "text_az": "Əvvəlcə Zona 3 (boş yer), sonra Zona 1, Zona 4 nəzərə alınmasın.", "text_en": "Zone 3 first (empty post), then Zone 1, ignore Zone 4", "text_ru": "Сначала зона 3 (незаполненная позиция), затем зона 1, зону 4 не учитывать"}, {"key": "D", "text_az": "Rəhbərə zəng edin və təlimatları gözləyin.", "text_en": "Call supervisor and wait for instructions", "text_ru": "Позвонить руководству и ждать инструкций"}]'::jsonb
WHERE id = '40000001-0000-0000-0000-000000000008';

UPDATE public.questions SET
    scenario_ru = 'После успешного мероприятия вы узнаёте, что двое участников вашей команды получили жалобы от посетителей за грубость. Как вы поступите?',
