UPDATE public.questions SET
    scenario_ru = 'Ваша организация проходит через реструктуризацию. Команда обеспокоена возможными сокращениями. Полной информацией вы пока не располагаете. Какой подход к руководству будет НАИБОЛЕЕ эффективным?',
    options = '[{"id": "a", "text": "Be transparent: share what you know, what you do not know, and when you expect to know more. Commit to updating them.", "score": 1.0, "text_ru": "Действовать открыто: сообщить, что вам известно, чего вы не знаете и когда ожидаете получить больше информации. Пообещать держать команду в курсе."}, {"id": "b", "text": "Reassure everyone that their jobs are safe even if you are not sure", "score": 0.1, "text_ru": "Заверить всех, что их должности в безопасности, даже если сами в этом не уверены"}, {"id": "c", "text": "Say nothing until you have complete information", "score": 0.2, "text_ru": "Ничего не говорить до тех пор, пока не будет исчерпывающей информации"}, {"id": "d", "text": "Redirect focus to current work and avoid discussing the restructuring", "score": 0.3, "text_ru": "Переключить внимание на текущую работу и избегать разговоров о реструктуризации"}]'::jsonb
WHERE id = 'e5000044-0000-4000-a000-000000000005';

UPDATE public.questions SET
    scenario_ru = 'Вы на полпути к завершению подробного проектного предложения, когда руководитель звонит и сообщает, что клиент существенно изменил требования. Большая часть уже выполненной работы не применима к новому объёму задач. Что вы делаете?',
    options = '[{"key": "A", "text_az": "Əvvəlcə hazırkı versiyanı bitirin — artıq əhəmiyyətli vaxt sərf etmisiniz", "text_en": "Finish the current version first — you have already invested significant time in it", "text_ru": "Доделать текущую версию до конца — вы уже вложили в неё значительное время"}, {"key": "B", "text_az": "Hazırkı işi istinad olaraq saxlayın, hansı bölmələrin yenidən istifadə oluna biləcəyini müəyyənləşdirin, yenilənmiş tələblərə uyğun yeni sənəd başladın, və yenidən işlənmiş cədvəl təyin edin", "text_en": "Save the current work as a reference, identify which sections can be reused, start a new document aligned with the updated requirements, and set a revised timeline", "text_ru": "Сохранить текущую работу как справочный материал, определить, какие разделы можно переиспользовать, начать новый документ в соответствии с обновлёнными требованиями и установить пересмотренные сроки"}, {"key": "C", "text_az": "Müştəriyə etiraz edin — tələbləri ortada dəyişdirmək qeyri-peşəkardır", "text_en": "Push back on the client — changing requirements midway is unprofessional", "text_ru": "Возразить клиенту — менять требования на полпути непрофессионально"}, {"key": "D", "text_az": "Dəyişiklik sizin qərarınız olmadığı üçün yenidən yazmağı menecerdən xahiş edin", "text_en": "Ask your manager to handle the rewrite since the change was not your decision", "text_ru": "Попросить руководителя самому заняться переработкой, поскольку решение об изменении было принято не вами"}]'::jsonb
WHERE id = 'a0000007-0000-0000-0000-000000000011';

UPDATE public.questions SET
    scenario_ru = 'С понедельника ваша команда переходит на новый инструмент управления проектами. Вы никогда им не пользовались. В пятницу у вас свободна вторая половина дня. Какой способ подготовки является НАИБОЛЕЕ эффективным?',
    options = '[{"key": "A", "text_az": "Bütün istifadəçi təlimatını əvvəldən sona oxuyun", "text_en": "Read the entire user manual from start to finish", "text_ru": "Прочитать всё руководство пользователя от начала до конца"}, {"key": "B", "text_az": "Alətin sürətli başlanğıc dərsini tamamlayın, sonra bazar ertəsi həqiqətən istifadə edəcəyiniz iş axınını sınamaq üçün hazırkı real tapşırıqlarınızdan birini yeni sistemdə yenidən yaradın", "text_en": "Complete the tool''s quick-start tutorial, then recreate one of your current real tasks in the new system to test the workflow you will actually use on Monday", "text_ru": "Пройти краткое вводное руководство по инструменту, а затем воссоздать в новой системе одну из текущих реальных задач, чтобы протестировать рабочий процесс, который понадобится в понедельник"}, {"key": "C", "text_az": "Bazar ertəsinə qədər gözləyin və edərək öyrənin — praktiki təcrübə ən yaxşı müəllimdir", "text_en": "Wait until Monday and learn by doing — hands-on experience is the best teacher", "text_ru": "Подождать до понедельника и учиться в процессе работы — практический опыт лучший учитель"}, {"key": "D", "text_az": "Alətin köhnəsindən həqiqətən daha yaxşı olub olmadığını anlamaq üçün YouTube rəylərini izləyin", "text_en": "Watch YouTube reviews to understand if the tool is actually better than the old one", "text_ru": "Посмотреть обзоры на YouTube, чтобы понять, действительно ли инструмент лучше предыдущего"}]'::jsonb
WHERE id = 'a0000007-0000-0000-0000-000000000012';

UPDATE public.questions SET
    scenario_ru = 'Вас перевели руководить новой командой, которая работает совсем иначе, чем предыдущая. В старой команде отлично работали ежедневные стендапы, жёсткие дедлайны и прямая обратная связь. Новая команда ценит самостоятельность, еженедельные встречи и письменное общение. После недели применения прежнего стиля моральный дух команды падает. Что вы делаете?',
    options = '[{"key": "A", "text_az": "Öz üslubunuzla davam edin — komandanın effektiv idarəetməyə uyğunlaşmağa vaxtı lazımdır", "text_en": "Continue with your style — the team needs time to adjust to effective management", "text_ru": "Продолжать в том же стиле — команде нужно время, чтобы привыкнуть к эффективному управлению"}, {"key": "B", "text_az": "Onların üstünlük verdikləri iş üslubunu anlamaq üçün komanda üzvləri ilə fərdi görüşün, sonra idarəetmə yanaşmanızı komandanın mədəniyyətinə uyğunlaşdırın, eyni zamanda dəyər əlavə edən rəhbərlik alət dəstinizdən elementləri tədricən təqdim edin", "text_en": "Meet with team members individually to understand their preferred working style, then adapt your management approach to match the team''s culture while gradually introducing elements from your leadership toolkit that add value", "text_ru": "Провести индивидуальные встречи с членами команды, чтобы понять предпочтительный для них стиль работы, затем адаптировать управленческий подход к культуре команды, постепенно внедряя элементы из своего арсенала руководителя, которые добавляют ценность"}, {"key": "C", "text_az": "Tamamilə komandanın mövcud üslubuna keçin — siz gəlməzdən əvvəl işləyirdisə, dəyişdirməyin", "text_en": "Switch entirely to the team''s existing style — if it was working before you arrived, do not change it", "text_ru": "Полностью перейти на существующий стиль команды — если он работал до вашего прихода, не стоит его менять"}, {"key": "D", "text_az": "HR-dən sizi idarəetmə üslubunuza uyğun gələn komandaya yenidən təyin etməsini xahiş edin", "text_en": "Ask HR to reassign you to a team that matches your management style", "text_ru": "Попросить HR перевести вас в команду, которая соответствует вашему стилю управления"}]'::jsonb
WHERE id = 'a0000007-0000-0000-0000-000000000013';

UPDATE public.questions SET
    scenario_ru = 'Ваша команда выпустила новую функцию по итогам 3 месяцев маркетинговых исследований. Через 2 недели показатель adoption составляет 8% — значительно ниже целевых 40%. Обратная связь от пользователей показывает, что функция решает реальную проблему, однако процесс онбординга вызывает затруднения. До следующего квартального обзора 6 недель. Какой ответ является НАИБОЛЕЕ адаптивным?',
    options = '[{"key": "A", "text_az": "Xüsusiyyətə daha çox vaxt verin — 2 həftə mühakimə etmək üçün çox erkəndir, istifadəçilərin onu kəşf etməsi üçün ən azı bir ay lazımdır", "text_en": "Give the feature more time — 2 weeks is too early to judge, users need at least a month to discover it", "text_ru": "Дать функции больше времени — 2 недели слишком рано делать выводы, пользователям нужен хотя бы месяц, чтобы её обнаружить"}, {"key": "B", "text_az": "İstifadəçi rəyinə əsasən onboarding axınını sadələşdirmək üçün sürətli 1 həftəlik sprint keçirin, yeni axını orijinalla A/B test edin, və rüblük baxışdan əvvəl aydın davam/dayandır meyarları ilə 3 həftəlik yoxlama nöqtəsi təyin edin", "text_en": "Run a rapid 1-week sprint to simplify the onboarding flow based on user feedback, A/B test the new flow against the original, and set a 3-week checkpoint with clear go/no-go criteria before the quarterly review", "text_ru": "Провести быстрый спринт продолжительностью 1 неделю, чтобы упростить процесс онбординга на основе обратной связи пользователей, провести A/B-тест нового варианта против исходного и установить контрольную точку через 3 недели с чёткими критериями «продолжать/остановить» до квартального обзора"}, {"key": "C", "text_az": "Xüsusiyyəti geri çəkin və sıfırdan yenidən dizayn edin — aşağı qəbul yanaşmanın səhv olduğunu sübut edir", "text_en": "Pull the feature and redesign it from scratch — the low adoption proves the approach was wrong", "text_ru": "Убрать функцию и разработать её заново с нуля — низкий показатель adoption доказывает, что подход был неверным"}, {"key": "D", "text_az": "Daha çox istifadəçini xüsusiyyətə yönləndirmək üçün marketinq xərclərini artırın — məlumatlılıq problemdir", "text_en": "Increase marketing spend to drive more users to the feature — awareness is the issue", "text_ru": "Увеличить маркетинговый бюджет, чтобы привлечь больше пользователей к функции — проблема в недостаточной осведомлённости"}]'::jsonb
WHERE id = 'a0000007-0000-0000-0000-000000000014';

UPDATE public.questions SET
    scenario_ru = 'Компания объявляет о масштабной реструктуризации: ваш отдел объединяется с другим, непосредственный руководитель уходит, половина команды переходит под начало нового руководителя, с которым вы никогда не работали, а ваша роль может расшириться. Переходный период — 3 месяца с ограниченной ясностью относительно итоговой структуры. Как НАИБОЛЕЕ эффективно действовать в этот период?',
    options = '[{"key": "A", "text_az": "Hər hansı addım atmadan yekun strukturun elan olunmasını gözləyin — natamam məlumata əsasən hərəkət etmək risklidir", "text_en": "Wait for the final structure to be announced before making any moves — acting on incomplete information is risky", "text_ru": "Дождаться объявления итоговой структуры, прежде чем предпринимать какие-либо шаги — действовать при неполной информации рискованно"}, {"key": "B", "text_az": "Proaktiv olaraq yeni rəhbərlə onların prioritetlərini anlamaq üçün görüşlər planlaşdırın, davamlılıq üçün komandanızın davam edən layihələrini və əsas biliklərini sənədləşdirin, birləşən şöbənin həmkarları ilə münasibətləri gücləndir, və genişlənmiş əhatə dairəsində bacarıqlarınızın dəyər əlavə edə biləcəyi 2-3 yol müəyyənləşdirin", "text_en": "Proactively schedule meetings with the new leader to understand their priorities, document your team''s ongoing projects and key knowledge for continuity, strengthen relationships with colleagues from the merging department, and identify 2-3 ways your skills can add value in the expanded scope", "text_ru": "Проактивно запланировать встречи с новым руководителем, чтобы понять его приоритеты; задокументировать текущие проекты и ключевые знания команды для обеспечения преемственности; укрепить отношения с коллегами из объединяемого отдела; определить 2–3 способа, которыми ваши навыки могут принести пользу в расширенном контексте"}, {"key": "C", "text_az": "Digər şöbələrdə rollar axtarmağa başlayın — yenidənqurmalar adətən ixtisarla nəticələnir", "text_en": "Start looking for roles in other departments — restructurings usually result in layoffs", "text_ru": "Начать искать позиции в других подразделениях — реструктуризации обычно сопровождаются сокращениями"}, {"key": "D", "text_az": "Yalnız hazırkı işinizə diqqət yetirin və həmişəki kimi çalışın — yaxşı iş görsəniz, yenidənqurma sizi təsir etməyəcək", "text_en": "Focus only on your current work and perform as usual — if you do good work, the restructuring will not affect you", "text_ru": "Сосредоточиться исключительно на текущей работе и выполнять её как обычно — если вы работаете хорошо, реструктуризация вас не затронет"}]'::jsonb
WHERE id = 'a0000007-0000-0000-0000-000000000015';

UPDATE public.questions SET
    scenario_ru = 'За 30 минут до начала вашей смены координатор сообщает, что вместо работы на стойке регистрации вас теперь направляют на информационную стойку. Вы никогда раньше не выполняли эту роль. Какова ваша ПЕРВАЯ реакция?',
    options = '[{"key": "A", "text_az": "İmtina — siz qeydiyyat üçün hazırlaşmısınız və dəyişiklik ədalətsizdir.", "text_en": "Refuse — you prepared for registration and switching is unfair", "text_ru": "Отказаться — вы готовились к регистрации, и такая замена несправедлива"}, {"key": "B", "text_az": "Qəbul edin, məlumat masasının vəzifələri haqqında qısa məlumatlandırma istəyin və hazırlaşın.", "text_en": "Accept, ask for a quick briefing on the information desk responsibilities, and get ready", "text_ru": "Согласиться, попросить краткий инструктаж об обязанностях на информационной стойке и подготовиться"}, {"key": "C", "text_az": "Qəbul edin, lakin rolu qeydiyyatı edəcəyiniz kimi dəqiq yerinə yetirin.", "text_en": "Accept but do the role exactly as you would have done registration", "text_ru": "Согласиться, но выполнять роль точно так же, как выполняли бы регистрацию"}, {"key": "D", "text_az": "Sözsüz qəbul edin və sual vermədən özünüz öhdəsindən gəlin.", "text_en": "Accept silently and figure it out on your own without asking questions", "text_ru": "Молча согласиться и разобраться самостоятельно, не задавая вопросов"}]'::jsonb
WHERE id = 'd0000001-0000-0000-0000-000000000001';

UPDATE public.questions SET
    scenario_ru = 'Основной докладчик опаздывает на 45 минут. Аудитория находится в зале и начинает проявлять нетерпение. Координатор ещё не дал вам никаких инструкций. Что вы делаете?',
    options = '[{"key": "A", "text_az": "Heç nə etməyin — hərəkətə başlamazdan əvvəl təlimatları gözləyin.", "text_en": "Do nothing — wait for instructions before acting", "text_ru": "Ничего не делать — ждать инструкций, прежде чем предпринимать какие-либо действия"}, {"key": "B", "text_az": "Diqqət mərkəzində qalmaq üçün auditoriya arasında dolaşın, sualları təmkinlə cavablandırın və koordinasiyaçınızla fəal şəkildə əlaqə saxlayın.", "text_en": "Circulate among the audience to stay visible, answer questions calmly, and proactively check in with your coordinator", "text_ru": "Перемещаться среди аудитории, чтобы оставаться в поле зрения, спокойно отвечать на вопросы и проактивно поддерживать связь с координатором"}, {"key": "C", "text_az": "Dinləyicilərə elan edin ki, spiker tezliklə gələcək.", "text_en": "Announce to the audience that the speaker will arrive soon", "text_ru": "Объявить аудитории, что докладчик скоро прибудет"}, {"key": "D", "text_az": "Növbəti günə yenidən planlaşdırılmasını təklif etmək", "text_en": "Suggest rescheduling to the next day", "text_ru": "Предложить перенести мероприятие на следующий день"}]'::jsonb
WHERE id = 'd0000001-0000-0000-0000-000000000002';

UPDATE public.questions SET
    scenario_ru = 'Коллега, отвечающий за VIP-зал, не выходит на смену. Вас просят подменить его в течение 2 часов, совмещая это со своими основными обязанностями. Как вы справляетесь с этой ситуацией?',
    options = '[{"key": "A", "text_az": "İmtina — bu sizin məsuliyyətiniz deyil.", "text_en": "Decline — it is not your responsibility", "text_ru": "Отказаться — это не ваша ответственность"}, {"key": "B", "text_az": "Qəbul edin, VİP zalının prioritetləri barədə sürətli təhvil-təslim alın, əhatə dairəsini koordinatorunuza bildirin və hər iki rol üzrə vaxtınızı idarə edin.", "text_en": "Accept, get a quick handover on VIP lounge priorities, communicate the coverage to your coordinator, and manage your time across both roles", "text_ru": "Согласиться, получить краткую передачу дел о приоритетах VIP-зала, сообщить о подмене координатору и грамотно распределить время между двумя ролями"}, {"key": "C", "text_az": "VIP-ə fokuslanmaq üçün orijinal rolunuzdan tamamilə imtina etməyi qəbul edin.", "text_en": "Accept and abandon your original role entirely to focus on VIP", "text_ru": "Согласиться и полностью оставить свои основные обязанности, чтобы сосредоточиться на VIP-зале"}, {"key": "D", "text_az": "Qəbul edin, lakin əvvəlcə İnsan Resurslarına rəsmi şikayət edin.", "text_en": "Accept but make a formal complaint to HR first", "text_ru": "Согласиться, но сначала подать официальную жалобу в HR"}]'::jsonb
WHERE id = 'd0000001-0000-0000-0000-000000000003';

UPDATE public.questions SET
    scenario_ru = 'За два часа до начала культурного мероприятия на открытом воздухе сильный дождь вынуждает перенести его в помещение меньшей площади. У вашей команды есть 30 минут на перестановку. Вы — самый опытный из присутствующих членов команды. Что вы делаете?',
    options = '[{"key": "A", "text_az": "Tədbir menecerinin hər kəsə təlimat verməsini gözləyin.", "text_en": "Wait for the event manager to give everyone instructions", "text_ru": "Ждать, пока менеджер мероприятия не даст инструкции всем"}, {"key": "B", "text_az": "Yeni məkanı dərhal qiymətləndirin, komanda üzvüləri prioritet tapşırıqlara təyin edin, planı çatdırın və vəziyyət barədə tədbir menecerinə hesabat verin.", "text_en": "Immediately assess the new space, assign team members to priority tasks, communicate the plan, and report status to the event manager", "text_ru": "Немедленно оценить новое помещение, распределить членов команды по приоритетным задачам, довести план до сведения всех и доложить о ситуации менеджеру мероприятия"}, {"key": "C", "text_az": "Tədbiri ləğv etməyi təklif edin.", "text_en": "Suggest cancelling the event", "text_ru": "Предложить отменить мероприятие"}, {"key": "D", "text_az": "Yalnız texniki quraşdırmaya cəmləşin.", "text_en": "Focus only on the tech setup", "text_ru": "Сосредоточиться исключительно на технической установке"}]'::jsonb
WHERE id = 'd0000001-0000-0000-0000-000000000004';

UPDATE public.questions SET
    scenario_ru = 'В разгар напряжённого мероприятия вы одновременно получаете: запрос от координатора с актуальными данными о количестве участников, обращение делегата с просьбой указать дорогу и вызов по рации о технической неисправности на площадке Б. Выполнить всё сразу невозможно. Что вы делаете?',
    options = '[{"key": "A", "text_az": "Onları daxilolma sırası ilə emal edin.", "text_en": "Handle them in the order received", "text_ru": "Обработать запросы в порядке поступления"}, {"key": "B", "text_az": "Cəld qiymətləndirmə aparın: hər üçünü təsdiqləyin, texniki problemi prioritetləşdirin, nümayəndəyə 10 saniyəlik təlimatlar verin və işçi sayını qısa mesajla göndərin.", "text_en": "Quickly triage: acknowledge all three, prioritize the tech issue, give the delegate 10-second directions, and send the headcount via a quick message", "text_ru": "Быстро расставить приоритеты: подтвердить получение всех трёх запросов, приоритизировать техническую неисправность, за 10 секунд объяснить делегату дорогу и отправить данные о количестве участников коротким сообщением"}, {"key": "C", "text_az": "Yalnız koordinatora diqqət yetirin — onlar ali səlahiyyət sahibidirlər.", "text_en": "Focus only on the coordinator — they are highest authority", "text_ru": "Сосредоточиться только на координаторе — он обладает наибольшими полномочиями"}, {"key": "D", "text_az": "Hər kəsə 5 dəqiqəyə ehtiyacınız olduğunu deyin.", "text_en": "Tell everyone you need 5 minutes", "text_ru": "Сообщить всем, что вам нужно 5 минут"}]'::jsonb
WHERE id = 'd0000001-0000-0000-0000-000000000005';

UPDATE public.questions SET
    scenario_ru = 'Вы допустили ошибку в системе печати бейджей, и 25 бейджей вышли с неправильными именами. Мероприятие начинается через 20 минут. Как вы себя чувствуете и какие шаги предпринимаете?',
    options = '[{"key": "A", "text_az": "Panikaya düşmək, utanmaq və səhvi gizlətmək", "text_en": "Panic, feel ashamed, and hide the error", "text_ru": "Паниковать, испытывать стыд и скрывать ошибку"}, {"key": "B", "text_az": "Gərginlik hiss etsəniz də, dərhal xətanı bildirin, nə qədərinin vaxtında yenidən çap edilə biləcəyini müəyyən edin və ən yüksək prioritetli olanları ilk olaraq yenidən çap etməyə başlayın.", "text_en": "Feel stressed but immediately report the error, assess how many can be reprinted in time, and start reprinting the highest-priority ones first", "text_ru": "Несмотря на стресс, немедленно сообщить об ошибке, оценить, сколько бейджей успеть перепечатать, и начать с наиболее приоритетных"}, {"key": "C", "text_az": "Səhv nişanları hər halda paylayın və qapıda izah edin.", "text_en": "Distribute the wrong badges anyway and explain at the door", "text_ru": "Всё равно раздать неверные бейджи и объяснять у входа"}, {"key": "D", "text_az": "Təqsirləndirilməməyiniz üçün bir həmkarınıza bunu bildirməyi tapşırın.", "text_en": "Ask a colleague to report it so you avoid blame", "text_ru": "Попросить коллегу сообщить об ошибке, чтобы избежать обвинений в свой адрес"}]'::jsonb
WHERE id = 'd0000001-0000-0000-0000-000000000006';

UPDATE public.questions SET
    scenario_ru = 'В ходе трёхдневного международного форума: 1-й день — зал для пленарного заседания затопило; 2-й день — 40% сотрудников ушли на больничный; 3-й день — программное обеспечение для мероприятия дало сбой в середине сессии. Всё это время вы были руководителем команды. Опишите, как вы адаптировались в каждый из дней.'
WHERE id = 'd0000001-0000-0000-0000-000000000007';

UPDATE public.questions SET
