WHERE id = 'd0000001-0000-0000-0000-000000000009';

UPDATE public.questions SET
    scenario_ru = 'Ваша смена официально заканчивается в 18:00. В 17:45 происходит серьёзный инцидент — ключевой руководитель группы получает травму и не может продолжать работу. У вас запланирован ужин в 19:00, который непросто отменить. Опишите, как вы будете действовать в этой ситуации.'
WHERE id = 'd0000001-0000-0000-0000-000000000010';

UPDATE public.questions SET
    scenario_ru = 'Ваша смена начинается в 09:00, но вы приходите в 08:45. Руководитель ещё не назначил вам рабочую позицию. Что вы делаете?',
    options = '[{"key": "A", "text_az": "Girişdə gözləyin.", "text_en": "Wait at the entrance", "text_ru": "Ждёте у входа."}, {"key": "B", "text_az": "Sizin rəhbərinizi tapın, tapşırığı təsdiq edin, quraşdırmaya kömək edin.", "text_en": "Find your supervisor, confirm assignment, help with setup", "text_ru": "Находите руководителя, уточняете назначение и помогаете с подготовкой."}, {"key": "C", "text_az": "Əvvəlcədən məlumat vermədən, harada olursa olsun kömək etməyə başlayın.", "text_en": "Start helping wherever without checking in", "text_ru": "Начинаете помогать там, где нужно, не согласовав это с руководителем."}, {"key": "D", "text_az": "Tam saat doqquzda qayıdın.", "text_en": "Return at exactly 09:00", "text_ru": "Возвращаетесь ровно в 09:00."}]'::jsonb
WHERE id = '50000001-0000-0000-0000-000000000001';

UPDATE public.questions SET
    scenario_ru = 'Посетитель задаёт вопрос, ответа на который вы не знаете. Информационная стойка находится в 200 м, и вы не можете покинуть свой пост. Что вы делаете?',
    options = '[{"key": "A", "text_az": "Onlara bilmədiyinizi bildirin və başqa birini tapmağı təklif edin.", "text_en": "Tell them you do not know, suggest finding someone else", "text_ru": "Сообщаете, что не знаете ответа, и предлагаете обратиться к кому-нибудь другому."}, {"key": "B", "text_az": "Ağlabatan cavab tərtib edin.", "text_en": "Make up a plausible answer", "text_ru": "Придумываете правдоподобный ответ."}, {"key": "C", "text_az": "Təsdiqləyin, həmkara əlaqə saxlayın və cavab əldə edərkən qonağı məlumatlandırın.", "text_en": "Acknowledge, radio a colleague, keep visitor informed while getting answer", "text_ru": "Принимаете вопрос, связываетесь с коллегой по рации и держите посетителя в курсе, пока ищете ответ."}, {"key": "D", "text_az": "Onları məlumat nöqtəsinə müşayiət etmək üçün iş yerinizi tərk edin.", "text_en": "Leave your post to walk them to the info point", "text_ru": "Покидаете пост, чтобы проводить посетителя к информационной стойке."}]'::jsonb
WHERE id = '50000001-0000-0000-0000-000000000002';

