UPDATE public.questions SET
    scenario_ru = 'Вы управляете стойкой аккредитации. Выстраивается длинная очередь, и принтер выходит из строя. Следующие 20 участников заранее зарегистрированы, но не могут получить бейджи. Что вы делаете?',
    options = '[{"key": "A", "text_az": "Xətti dayandırın və IT-nin printeri təmir etməsini gözləyin.", "text_en": "Stop the line and wait for IT to fix the printer", "text_ru": "Останавливаете очередь и ждёте, пока IT-специалисты починят принтер."}, {"key": "B", "text_az": "Rəqəmsal olaraq təsdiqləmək, müvəqqəti əlyazma icazə vərəqəsi vermək, rəhbəri məlumatlandırmaq.", "text_en": "Verify digitally, provide temp handwritten pass, notify supervisor", "text_ru": "Проверяете регистрацию в электронном виде, выдаёте временный пропуск, написанный от руки, и уведомляете руководителя."}, {"key": "C", "text_az": "Printer təmir edilənədək şəxsləri uzaqlaşdırın.", "text_en": "Turn people away until printer is fixed", "text_ru": "Просите людей вернуться позже — до устранения неисправности принтера."}, {"key": "D", "text_az": "Hər kəsi doğrulama olmadan içəri buraxın.", "text_en": "Let everyone in without verification", "text_ru": "Пропускаете всех без проверки."}]'::jsonb
WHERE id = '50000001-0000-0000-0000-000000000004';

UPDATE public.questions SET
    scenario_ru = 'Вы одновременно отвечаете за сопровождение VIP-группы, управление очередью и ответы на вызовы по рации. Как вы действуете?',
    options = '[{"key": "A", "text_az": "Bütün diqqəti VIP-ə yönəltmək — ən yüksək prioritet.", "text_en": "Focus entirely on VIP — highest priority", "text_ru": "Сосредотачиваетесь полностью на VIP-группе — она имеет наивысший приоритет."}, {"key": "B", "text_az": "Trij: Növbəni yaxınlıqdakı komanda üzvüyə təhvil vermək, radioya qısaca cavab vermək, sonra VIP-lə məşğul olmaq.", "text_en": "Triage: hand off queue to nearby team member, answer radio briefly, then VIP", "text_ru": "Расставляете приоритеты: передаёте очередь ближайшему коллеге, кратко отвечаете по рации, затем занимаетесь VIP-группой."}, {"key": "C", "text_az": "Fiziki işləri yerinə yetirərkən radioya diqqət etməyin.", "text_en": "Ignore radio while handling physical tasks", "text_ru": "Игнорируете рацию, пока выполняете задачи на месте."}, {"key": "D", "text_az": "Dayanın və koordinatordan ilk hansı tapşırığın olduğunu soruşun.", "text_en": "Stop and ask coordinator which task first", "text_ru": "Останавливаетесь и спрашиваете у координатора, какая задача первоочередная."}]'::jsonb
WHERE id = '50000001-0000-0000-0000-000000000005';

