    scenario_ru = 'Из-за технической неисправности, не зависящей от вас, ваш участок отстаёт от расписания на 45 минут. Как вы минимизируете неудобства для участников?'
WHERE id = '50000001-0000-0000-0000-000000000006';

UPDATE public.questions SET
    scenario_ru = '80 членов команды прибывают на регистрацию в течение 15 минут, а система работает медленно. Как вы предотвратите образование очереди?'
WHERE id = '50000001-0000-0000-0000-000000000007';

UPDATE public.questions SET
    scenario_ru = 'Во время церемонии закрытия в вашей зоне неожиданно отключается электричество. В зале находятся 300 участников, освещения и звука нет. В вашем распоряжении рация и фонарик. Ваши действия в первые 60 секунд?',
    options = '[{"key": "A", "text_az": "Kəsilmə barədə radio vasitəsilə məlumat verin, ən yaxın çıxışı əl fənəri ilə işıqlandırın, iştirakçılara yerlərində qalmaları barədə sakitcə təlimat verin.", "text_en": "Radio the outage, illuminate nearest exit with flashlight, calmly instruct attendees to stay in place", "text_ru": "Сообщаете об отключении по рации, освещаете ближайший выход фонариком и спокойно просите участников оставаться на своих местах."}, {"key": "B", "text_az": "Elektrik panelini özünüz tapın.", "text_en": "Find the electrical panel yourself", "text_ru": "Самостоятельно ищете электрощит."}, {"key": "C", "text_az": "Rəsmi təlimatları gözləyin.", "text_en": "Wait for official instructions", "text_ru": "Ждёте официальных инструкций."}, {"key": "D", "text_az": "Hər kəsin dərhal təxliyə olunmasını təmin edin.", "text_en": "Direct everyone to evacuate immediately", "text_ru": "Организуете немедленную эвакуацию всех присутствующих."}]'::jsonb
WHERE id = '50000001-0000-0000-0000-000000000008';

UPDATE public.questions SET
    scenario_ru = 'Вы в одиночку управляете транспортной стойкой. Одновременно подходят три делегата: у одного потерян бейдж, второй опаздывает на шаттл, третий сообщает об изменении в последний момент. Все трое раздражены. Что вы делаете?',
    options = '[{"key": "A", "text_az": "Onları gəliş sırası ilə bir-bir emal edin.", "text_en": "Handle them one by one in arrival order", "text_ru": "Обслуживаете каждого по очереди в порядке прихода."}, {"key": "B", "text_az": "Prioritetləşdirmə:\nHər üçünü nəzərə almaq,\nŞattl məsələsini radio ilə bildirmək,\nNişanlı şəxsdən 90 saniyə gözləməsini xahiş etmək,\nNəqliyyat dəyişikliyini tənzimləmək.", "text_en": "Triage: acknowledge all three, radio the shuttle issue, ask badge person to wait 90 sec, handle transport change", "text_ru": "Расставляете приоритеты: принимаете всех троих, сообщаете о проблеме с шаттлом по рации, просите человека с бейджем подождать 90 секунд и решаете вопрос с изменением в транспорте."}, {"key": "C", "text_az": "Onlara növbəyə düzülmələrini tapşırın.", "text_en": "Ask them to form a queue", "text_ru": "Просите их встать в очередь."}, {"key": "D", "text_az": "Supervayzeri çağırın və üçünü də təhvil verin.", "text_en": "Call supervisor and hand all three over", "text_ru": "Вызываете руководителя и передаёте ему всех троих."}]'::jsonb
WHERE id = '50000001-0000-0000-0000-000000000009';

UPDATE public.questions SET
    scenario_ru = 'После 10-часовой смены на фестивале напишите структурированный отчёт: что прошло хорошо, что не получилось, что вы сделали бы иначе и что вам необходимо от организационной команды.'
WHERE id = '50000001-0000-0000-0000-000000000010';

UPDATE public.questions SET
    scenario_ru = 'Вы прибываете на конференц-площадку за 2 часа до открытия дверей. В вашем списке 8 задач: установка AV-оборудования, стойка регистрации, навигационные указатели, координация питания, регистрация спикеров, тестирование Wi-Fi, инструктаж фотографа и обход охраны. В вашем распоряжении команда из 4 человек. Какое первое действие будет НАИЛУЧШИМ?',
    options = '[{"key": "A", "text_az": "Ən mürəkkəb olduğu üçün AV quraşdırma ilə başlayın və siyahını sıra ilə keçin", "text_en": "Start with AV setup since it is the most complex and work through the list in order", "text_ru": "Начинаете с установки AV-оборудования как наиболее сложной задачи и последовательно выполняете список по порядку."}, {"key": "B", "text_az": "Tapşırıqları asılılıq və son tarixə görə prioritetləşdirin: əvvəlcə AV və Wi-Fi təyin edin (digər tapşırıqları bloklaşdırır), müstəqil tapşırıqları komanda üzvlərinə paralel həvalə edin və 90 dəqiqəlik yoxlama nöqtəsi təyin edin", "text_en": "Prioritize tasks by dependency and deadline: assign AV and Wi-Fi first (they block other tasks), delegate independent tasks in parallel to team members, and set a 90-minute checkpoint", "text_ru": "Расставляете приоритеты по зависимостям и срокам: сначала поручаете установку AV и тестирование Wi-Fi (они блокируют остальные задачи), параллельно делегируете независимые задачи членам команды и назначаете контрольную точку через 90 минут."}, {"key": "C", "text_az": "Siyahını bərabər bölün — hər adama 2 tapşırıq — və hər şey bitdikdə yoxlayın", "text_en": "Split the list evenly — 2 tasks per person — and check back when everything is done", "text_ru": "Делите список поровну — по 2 задачи на человека — и сверяетесь, когда всё будет выполнено."}, {"key": "D", "text_az": "Hər hansı tapşırıq təyin etməzdən əvvəl planı anlamaq üçün əvvəlcə məkanı tamamilə gəzin", "text_en": "Do a full walkthrough of the venue yourself first to understand the layout before assigning any tasks", "text_ru": "Сначала самостоятельно полностью обходите площадку, чтобы разобраться в планировке, и только затем распределяете задачи."}]'::jsonb
WHERE id = 'e0000005-0000-0000-0000-000000000011';

UPDATE public.questions SET
    scenario_ru = 'За 30 минут до начала семинара проектор в главном зале выходит из строя. Ожидается 60 участников. В меньшем зале с рабочим проектором вмещается только 30 человек. Что вы делаете?',
    options = '[{"key": "A", "text_az": "Proyeksiyanı ləğv edin və əvəzinə çap materialları paylayın — proyektor yoxdur, slayd yoxdur", "text_en": "Cancel the projection and print handouts instead — no projector, no slides", "text_ru": "Отказываетесь от проекции и раздаёте печатные материалы — нет проектора, нет слайдов."}, {"key": "B", "text_az": "İştirakçıları iki qrupa bölün: kiçik otaqdan istifadə edərək seminari iki dəfə keçirin, hər iki sessiyaya uyğunlaşmaq üçün cədvəli tənzimləyin", "text_en": "Split participants into two groups: run the workshop twice using the smaller room, adjusting the schedule to accommodate both sessions", "text_ru": "Делите участников на две группы: проводите семинар дважды в меньшем зале, корректируя расписание с учётом обеих сессий."}, {"key": "C", "text_az": "Hər kəsi kiçik otağa köçürün və 30 nəfərdən ayaq üstə dayanmağı xahiş edin", "text_en": "Move everyone to the smaller room and ask 30 people to stand", "text_ru": "Переводите всех в меньший зал и просите 30 человек стоять."}, {"key": "D", "text_az": "Bir saat çəksə belə, İT proyektoru düzəldənə qədər seminarı gecikdirin", "text_en": "Delay the workshop until IT fixes the projector, even if it takes an hour", "text_ru": "Переносите семинар до устранения неисправности проектора IT-специалистами, даже если это займёт час."}]'::jsonb
WHERE id = 'e0000005-0000-0000-0000-000000000012';

UPDATE public.questions SET
    scenario_ru = 'Вы координируете корпоративный саммит с участием 3 внешних подрядчиков (питание, AV, охрана), 2 внутренних команд (маркетинг, операции) и VIP-спикера, прилетающего из-за рубежа. За день до мероприятия подрядчик по питанию сообщает по электронной почте, что грузовик сломался и еда прибудет на 3 часа позже — уже в ходе самого мероприятия. Какой НАИЛУЧШИЙ план действий?',
    options = '[{"key": "A", "text_az": "Gecikməni qəbul edin və naharı 3 saat geri çəkmək üçün tədbir cədvəlini tənzimləyin", "text_en": "Accept the delay and adjust the event schedule to push lunch back by 3 hours", "text_ru": "Принимаете задержку и сдвигаете обед в расписании мероприятия на 3 часа позже."}, {"key": "B", "text_az": "Dərhal iki ehtiyat iaşə seçimi ilə əlaqə saxlayın, əsas maddələr (qəhvə, su, qəlyanaltı) üçün orijinal təchizatçıdan qismən çatdırılma barədə danışıq aparın, və hər iki ssenarini əhatə edən ehtiyat cədvəli ilə yenidən işlənmiş tədbir axını hazırlayın", "text_en": "Contact two backup catering options immediately, negotiate partial delivery from the original vendor for essentials (coffee, water, snacks), and prepare a revised event flow with a contingency timeline that covers both scenarios", "text_ru": "Немедленно связываетесь с двумя резервными поставщиками питания, договариваетесь с основным подрядчиком о частичной доставке самого необходимого (кофе, вода, закуски) и готовите обновлённую программу мероприятия с планом на оба сценария."}, {"key": "C", "text_az": "İaşəni tamamilə ləğv edin və iştirakçılara öz naharlarını gətirmələrini bildirin", "text_en": "Cancel catering entirely and inform attendees to bring their own lunch", "text_ru": "Полностью отменяете питание и сообщаете участникам, что они должны принести обед с собой."}, {"key": "D", "text_az": "Təchizatçıya zəng edin və problemi həll etmələrini israr edin — bu onların məsuliyyətidir", "text_en": "Call the vendor and insist they fix the problem — it is their responsibility", "text_ru": "Звоните подрядчику и настаиваете на том, чтобы он решил проблему — это его ответственность."}]'::jsonb
WHERE id = 'e0000005-0000-0000-0000-000000000013';

UPDATE public.questions SET
    scenario_ru = 'Во время конференции с 500 участниками вы замечаете, что очередь на регистрацию выросла до 80+ человек, а среднее время оформления составляет 4 минуты на человека. До начала открывающего пленарного доклада остаётся 25 минут. На регистрации работают 3 сотрудника, ещё 2 члена команды свободны. Какое НАИБОЛЕЕ эффективное немедленное действие?',
    options = '[{"key": "A", "text_az": "Növbədəki insanlardan səbirli olmalarını xahiş edin — lazım olsa əsas çıxış gec başlayacaq", "text_en": "Ask people in the queue to be patient — the keynote will start late if needed", "text_ru": "Просите стоящих в очереди проявить терпение — при необходимости доклад начнётся позже."}, {"key": "B", "text_az": "2 gəzən üzvü 2 əlavə qeydiyyat xətti açmaq üçün yenidən yerləşdirin, bir əməkdaşa növbəni nişan növünə görə (əvvəlcədən qeydiyyatdan keçmiş vs yerində gələn) əvvəlcədən sıralasın, və hələ növbədə olanlara əsas çıxışın foyedə canlı yayımlanacağını elan edin", "text_en": "Redeploy the 2 roaming members to open 2 additional check-in lanes, have one staff member pre-sort the queue by badge type (pre-registered vs walk-in), and announce the keynote will be livestreamed in the lobby for those still in line", "text_ru": "Перенаправляете 2 свободных сотрудника на открытие 2 дополнительных линий регистрации, поручаете одному сотруднику предварительно разделить очередь по типу бейджа (предварительная регистрация и регистрация на месте), объявляете, что для тех, кто ещё в очереди, доклад будет транслироваться в прямом эфире в фойе."}, {"key": "C", "text_az": "İştirakçılara qeydiyyatı ötürmələrinə və əsas çıxışdan sonra qeydiyyatdan keçmələrinə icazə verin", "text_en": "Let attendees skip registration and check in after the keynote", "text_ru": "Разрешаете участникам пропустить регистрацию и оформиться после пленарного доклада."}, {"key": "D", "text_az": "Əsas çıxışı 30 dəqiqə gecikdirin və dəyişikliyi elan edin", "text_en": "Delay the keynote by 30 minutes and announce the change", "text_ru": "Переносите начало пленарного доклада на 30 минут и объявляете об изменении."}]'::jsonb
WHERE id = 'e0000005-0000-0000-0000-000000000014';

UPDATE public.questions SET
    scenario_ru = 'После крупного мероприятия по запуску продукта вы получаете неоднозначные отзывы: удовлетворённость содержательной частью составила 92%, а логистикой (ожидание на регистрации, переходы между залами, парковка) — лишь 58%. Руководство просит вас представить план улучшений для следующего мероприятия. Какой подход к анализу будет НАИБОЛЕЕ ценным?',
    options = '[{"key": "A", "text_az": "Məzmun yaxşı bal aldığına görə planı logistika məsələlərinə yönəldin — işləyəni təhlil etməyə ehtiyac yoxdur", "text_en": "Focus the plan on the logistics issues since content scored well — no need to analyze what worked", "text_ru": "Сосредотачиваете план на проблемах с логистикой, так как содержание получило высокую оценку, — анализировать то, что сработало, нет необходимости."}, {"key": "B", "text_az": "Hər logistika uğursuzluğunu kök səbəbinə uyğunlaşdırın (kifayət qədər kadr olmaması, məkan planı, təchizatçı gecikməsi), hər iştirakçı üçün itirilmiş dəqiqələrdə təsiri kəmiyyətləndirin, sənaye standartları ilə müqayisə edin, və xərc-effektivliyə görə sıralanmış həll yollarını proqnozlaşdırılan təkmilləşdirmə faizləri ilə təklif edin", "text_en": "Map each logistics failure to its root cause (understaffing, venue layout, vendor delay), quantify the impact in minutes lost per attendee, benchmark against industry standards, and propose solutions ranked by cost-effectiveness with projected improvement percentages", "text_ru": "Определяете корневую причину каждого логистического сбоя (нехватка персонала, планировка площадки, задержка подрядчика), рассчитываете потери в минутах на каждого участника, сравниваете с отраслевыми стандартами и предлагаете решения, ранжированные по соотношению затрат и эффективности с прогнозируемыми показателями улучшения."}, {"key": "C", "text_az": "Nəyin səhv getdiyini dəqiq anlamaq üçün daha ətraflı suallarla iştirakçıları yenidən sorğulayın", "text_en": "Survey attendees again with more detailed questions to understand exactly what went wrong", "text_ru": "Повторно опрашиваете участников с более детальными вопросами, чтобы точно понять, что пошло не так."}, {"key": "D", "text_az": "Növbəti tədbir üçün peşəkar tədbir idarəetmə şirkəti işə götürün — onlar logistikanı idarə edəcəklər", "text_en": "Hire a professional event management company for the next event — they will handle logistics", "text_ru": "Нанимаете профессиональную компанию по организации мероприятий для следующего события — они возьмут на себя логистику."}]'::jsonb
WHERE id = 'e0000005-0000-0000-0000-000000000015';

UPDATE public.questions SET
    scenario_ru = 'На входе в мероприятие вам выдают ручной сканер бейджей. Каждый раз при сканировании бейджа участника сканер подаёт красный звуковой сигнал. Каково ваше ПЕРВОЕ действие?',
    options = '[{"key": "A", "text_az": "Skan etməyə davam edin və öz-özünə düzələcəyinə ümid edin.", "text_en": "Keep scanning and hope it fixes itself", "text_ru": "Продолжайте сканировать в надежде, что проблема решится сама собой"}, {"key": "B", "text_az": "Skanerin qoşulu olub-olmadığını yoxlayın, onu yenidən başladın və təsdiqləmək üçün sınaq nişanını skan edin.", "text_en": "Check if the scanner is connected, restart it, and scan a test badge to confirm", "text_ru": "Проверьте подключение сканера, перезагрузите его и отсканируйте тестовый бейдж для проверки"}, {"key": "C", "text_az": "Girişdəki bütün nişan skanerlərini dərhal əvəz edin.", "text_en": "Immediately replace all badge scanners at the entrance", "text_ru": "Немедленно замените все сканеры бейджей на входе"}, {"key": "D", "text_az": "Nümayəndələrdən skan etmədən daxil olmalarını xahiş edin və onları əl ilə kağız üzərində qeyd edin.", "text_en": "Ask delegates to enter without scanning and log them manually on paper", "text_ru": "Попросите участников войти без сканирования и зарегистрируйте их вручную на бумаге"}]'::jsonb
WHERE id = '60000001-0000-0000-0000-000000000001';

UPDATE public.questions SET
    scenario_ru = 'Вам срочно нужно связаться с руководителем вашей команды по рации. Другая команда уже ведёт переговоры на этом канале. Как следует поступить?',
    options = '[{"key": "A", "text_az": "Ötürə basın və onlara danışın.", "text_en": "Press transmit and speak over them", "text_ru": "Нажмите кнопку передачи и говорите поверх них"}, {"key": "B", "text_az": "Ötürməzdən əvvəl fasiləni gözləyin, sonra çağırış işarənizi və təcili mesajınızı bildirin.", "text_en": "Wait for a pause, then say your call sign and urgent message before transmitting", "text_ru": "Дождитесь паузы в эфире, затем назовите свой позывной и передайте срочное сообщение"}, {"key": "C", "text_az": "Komanda rəhbərinizə məlumatlandırmadan başqa kanala keçmək", "text_en": "Switch to a different channel without notifying your team leader", "text_ru": "Переключитесь на другой канал, не предупредив руководителя команды"}, {"key": "D", "text_az": "Bunun əvəzinə WhatsApp mesajı göndərin.", "text_en": "Send a WhatsApp message instead", "text_ru": "Отправьте сообщение в WhatsApp вместо рации"}]'::jsonb
WHERE id = '60000001-0000-0000-0000-000000000003';

UPDATE public.questions SET
    scenario_ru = 'Онлайн-система регистрации зависла, пока у вашей стойки выстроилась очередь из 40 участников. Система не отвечает уже 2 минуты. Какой план действий является НАИЛУЧШИМ?',
    options = '[{"key": "A", "text_az": "Səhifəni hər 10 saniyədən bir yeniləyin.", "text_en": "Keep refreshing the page every 10 seconds", "text_ru": "Обновляйте страницу каждые 10 секунд"}, {"key": "B", "text_az": "Dərhal oflayn ehtiyat siyahısına keçin, adları əl ilə qeyd edin və texniki rəhbərinizə məlumat verin.", "text_en": "Switch to the offline backup list immediately, log names manually, and notify your tech lead", "text_ru": "Немедленно переключитесь на офлайн-резервный список, вносите имена вручную и сообщите техническому руководителю"}, {"key": "C", "text_az": "Bütün nümayəndələrdən telefonlarında yenidən qeydiyyatdan keçmələrini xahiş edin.", "text_en": "Ask all delegates to register again on their phones", "text_ru": "Попросите всех участников зарегистрироваться повторно через свои телефоны"}, {"key": "D", "text_az": "Masanı bağlayın və İT-nin sistemi təmir etməsini gözləyin.", "text_en": "Close the desk and wait for IT to fix the system", "text_ru": "Закройте стойку и дождитесь, пока ИТ-специалисты устранят неполадку"}]'::jsonb
WHERE id = '60000001-0000-0000-0000-000000000004';

UPDATE public.questions SET
    scenario_ru = 'За 5 минут до начала сессии ноутбук докладчика не подключается к проектору. Кабель HDMI вставлен, но экран остаётся чёрным. С какого шага диагностики следует начать ПЕРВЫМ?',
    options = '[{"key": "A", "text_az": "HDMI kabelini yenisi ilə əvəz edin.", "text_en": "Replace the HDMI cable with a new one", "text_ru": "Замените HDMI-кабель на новый"}, {"key": "B", "text_az": "Noutbukda ekran keçidi qısa yolunu (Windows+P və ya Fn+F düyməsi) sıxın.", "text_en": "Press the display toggle shortcut (Windows+P or Fn+F key) on the laptop", "text_ru": "Нажмите сочетание клавиш для переключения дисплея (Windows+P или Fn+F) на ноутбуке"}, {"key": "C", "text_az": "Proyektoru əsas elektrik panelindən yenidən başladın.", "text_en": "Restart the projector from the main power panel", "text_ru": "Перезапустите проектор с главной панели управления питанием"}, {"key": "D", "text_az": "Məruzəçidən başqa bir noutbukdan istifadə etməsini xahiş edin.", "text_en": "Ask the speaker to use a different laptop", "text_ru": "Попросите докладчика воспользоваться другим ноутбуком"}]'::jsonb
WHERE id = '60000001-0000-0000-0000-000000000005';

UPDATE public.questions SET
    scenario_ru = 'После мероприятия вы обнаруживаете, что таблица учёта присутствия сотрудников — содержащая полные имена, номера телефонов и удостоверения личности — была открыта с доступом «Все, у кого есть ссылка, могут редактировать». Что следует сделать?',
    options = '[{"key": "A", "text_az": "Yaxşıdır, tədbir başa çatdığı üçün məlumat artıq həssas deyil.", "text_en": "It is fine — the event is over so the data is no longer sensitive", "text_ru": "Всё в порядке — мероприятие завершено, данные больше не являются конфиденциальными"}, {"key": "B", "text_az": "Paylaşım icazəsini dərhal məhdudlaşdırın və koordinatorunuzu məlumatlandırın.", "text_en": "Change the sharing permission to restricted immediately and inform your coordinator", "text_ru": "Немедленно ограничьте права доступа и уведомите координатора"}, {"key": "C", "text_az": "Hər hansı bir dəyişiklik etməzdən əvvəl, özünüz üçün ehtiyat olaraq bir nüsxəsini endirin.", "text_en": "Download a copy for yourself as backup before changing anything", "text_ru": "Прежде чем что-либо менять, скачайте копию себе в качестве резервной"}, {"key": "D", "text_az": "Sui-istifadənin qarşısını almaq üçün elektron cədvəli tamamilə silmək.", "text_en": "Delete the spreadsheet entirely to prevent misuse", "text_ru": "Полностью удалите таблицу, чтобы исключить возможность злоупотребления"}]'::jsonb
WHERE id = '60000001-0000-0000-0000-000000000006';

UPDATE public.questions SET
    scenario_ru = 'Вы прибываете за 90 минут до начала конференции на 200 человек, чтобы подготовить техническую стойку: 4 сканера бейджей, 2 ноутбука для регистрации, рации для 8 членов команды и таблица учёта присутствия в режиме реального времени. Опишите процесс подготовки и проверки оборудования.'
WHERE id = '60000001-0000-0000-0000-000000000007';

UPDATE public.questions SET
    scenario_ru = 'В разгар мероприятия приложение для координации персонала вышло из строя, а 2-й канал рации заполнен помехами. Вы управляете 6 подкомандами, рассредоточенными по 3 этажам. Как вы будете поддерживать координацию?'
WHERE id = '60000001-0000-0000-0000-000000000008';

UPDATE public.questions SET
    scenario_ru = 'Вы ведёте Google Таблицу с данными 150 сотрудников. В столбце B указаны их имена, в столбце C — «Присутствует» или «Отсутствует». Координатор просит вас быстро подсчитать, сколько человек присутствует. Опишите точно, что именно вы введёте или сделаете.'
WHERE id = '60000001-0000-0000-0000-000000000009';

UPDATE public.questions SET
    scenario_ru = 'Прибывают 10 новых членов команды, которые ни разу не работали с платформой управления мероприятиями, используемой вашей организацией. У вас есть 20 минут, чтобы все они могли приступить к работе до открытия дверей. Опишите ваш подход к вводному обучению.'
WHERE id = '60000001-0000-0000-0000-000000000010';

UPDATE public.questions SET
    scenario_ru = 'Коллега поделился бесплатным онлайн-инструментом для конвертации PDF-счетов в таблицы. Инструмент предлагает загрузить счета клиентов, содержащие имена, суммы и банковские реквизиты. У вашей компании нет политики в отношении сторонних инструментов. Что следует сделать ПЕРВЫМ?',
    options = '[{"key": "A", "text_az": "İstifadə edin — həmkarınız artıq sınayıb və işləyir", "text_en": "Use it — the colleague already tried it and it works", "text_ru": "Воспользуйтесь им — коллега уже проверил, всё работает"}, {"key": "B", "text_az": "Alətin gizlilik siyasətini yoxlayın, yüklənmiş məlumatları saxlayıb-saxlamadığını yoxlayın, və hər hansı müştəri məlumatını yükləməzdən əvvəl İT və ya uyğunluq komandanıza müraciət edin", "text_en": "Check the tool''s privacy policy, verify whether it stores uploaded data, and consult your IT or compliance team before uploading any client data", "text_ru": "Ознакомьтесь с политикой конфиденциальности инструмента, выясните, сохраняет ли он загружаемые данные, и проконсультируйтесь с ИТ-отделом или службой комплаенса, прежде чем загружать любые данные клиентов"}, {"key": "C", "text_az": "Əvvəlcə işlədiyini görmək üçün saxta məlumatla sınaq faylı yükləyin, sonra real faturaları yükləyin", "text_en": "Upload a test file with fake data first to see if it works, then upload real invoices", "text_ru": "Сначала загрузите тестовый файл с вымышленными данными, чтобы убедиться в работоспособности, а затем загрузите реальные счета"}, {"key": "D", "text_az": "Alətdən uzaq durun və PDF-ləri əl ilə çevirin — ehtiyatlı olmaq daha yaxşıdır", "text_en": "Avoid the tool and convert PDFs manually — better safe than sorry", "text_ru": "Откажитесь от инструмента и конвертируйте PDF вручную — береженого бог бережёт"}]'::jsonb
WHERE id = 'd0000006-0000-0000-0000-000000000011';

UPDATE public.questions SET
    scenario_ru = 'Ваша команда использует дашборд управления проектами. Вы замечаете, что показатель выполнения задач составляет 95%, тогда как индекс удовлетворённости клиентов — 62%. Менеджер спрашивает: «Мы хорошо работаем?» Какой ответ является НАИЛУЧШИМ?',
    options = '[{"key": "A", "text_az": "Bəli — 95% tamamlanma hər standarta görə əla performansdır", "text_en": "Yes — 95% completion is excellent performance by any standard", "text_ru": "Да — 95% выполнения задач является отличным показателем по любым стандартам"}, {"key": "B", "text_az": "Rəqəmlər göstərir ki, tapşırıqları vaxtında tamamlayırıq, lakin nəticə müştəri gözləntilərini qarşılamaya bilər. Keyfiyyət, əhatə dairəsi, yoxsa kommunikasiya problemi olduğunu öyrənmək üçün tamamlanma dərəcəsi və məmnunluq arasındakı fərqi araşdırmalıyıq", "text_en": "The numbers suggest we are completing tasks on time but the output may not be meeting client expectations. We should investigate the gap between completion rate and satisfaction to find out if it is a quality, scope, or communication issue", "text_ru": "Цифры говорят о том, что задачи выполняются в срок, однако результаты, возможно, не отвечают ожиданиям клиентов. Необходимо разобраться в причинах расхождения между выполнением задач и уровнем удовлетворённости — это может быть вопрос качества, охвата или коммуникации"}, {"key": "C", "text_az": "Məmnunluq balı yəqin ki, səhvdir — 95% tamamlanma ilə müştərilər razı olmalıdır", "text_en": "The satisfaction score is probably wrong — with 95% completion, clients should be happy", "text_ru": "Индекс удовлетворённости, вероятно, ошибочен — при 95% выполнения задач клиенты должны быть довольны"}, {"key": "D", "text_az": "Yalnız məmnunluq balına diqqət yetirməliyik — müştərilər narazıdırsa tamamlanma dərəcəsinin əhəmiyyəti yoxdur", "text_en": "We need to focus only on the satisfaction score — completion rate does not matter if clients are unhappy", "text_ru": "Нужно сосредоточиться исключительно на индексе удовлетворённости — если клиенты недовольны, показатель выполнения задач не имеет значения"}]'::jsonb
WHERE id = 'd0000006-0000-0000-0000-000000000012';

UPDATE public.questions SET
    scenario_ru = 'Каждый понедельник утром команда тратит 3 часа на ручное копирование данных из почтовых отчётов в общую таблицу. Отчётов 15, формат у всех одинаковый. Коллега предлагает автоматизировать этот процесс. У вас есть доступ к Google Workspace и базовым no-code-инструментам. Каков НАИБОЛЕЕ эффективный первый шаг?',
    options = '[{"key": "A", "text_az": "Bütün 15 hesabatı emal edən tam avtomatlaşdırma qurun — ya tam, ya heç", "text_en": "Build a full automation that processes all 15 reports — go big or go home", "text_ru": "Настройте полную автоматизацию сразу для всех 15 отчётов — либо всё, либо ничего"}, {"key": "B", "text_az": "Ən sadə formatlı 2-3 hesabatı avtomatlaşdırmaqla başlayın, dəqiqliyi əl ilə olan nəticələrlə yoxlayın, sonra iş axını sübut edildikdən sonra hamısına 15-ə genişləndirin", "text_en": "Start by automating 2-3 reports with the simplest format, validate accuracy against manual results, then scale to all 15 once the workflow is proven", "text_ru": "Начните с автоматизации 2–3 отчётов наиболее простого формата, сверьте точность с результатами ручной обработки, а затем масштабируйте на все 15, когда рабочий процесс будет подтверждён"}, {"key": "C", "text_az": "Xüsusi həll qurmaq üçün proqramçı işə götürün — no-code alətlər biznes məlumatları üçün etibarlı deyil", "text_en": "Hire a developer to build a custom solution — no-code tools are not reliable for business data", "text_ru": "Наймите разработчика для создания индивидуального решения — no-code-инструменты ненадёжны для бизнес-данных"}, {"key": "D", "text_az": "Əl ilə prosesi saxlayın, lakin bunu etmək üçün stajyer işə götürün — həftədə cəmi 3 saatdır", "text_en": "Keep the manual process but hire an intern to do it — it is only 3 hours per week", "text_ru": "Оставьте ручной процесс, но наймите стажёра для его выполнения — это всего 3 часа в неделю"}]'::jsonb
WHERE id = 'd0000006-0000-0000-0000-000000000013';

UPDATE public.questions SET
    scenario_ru = 'Вы используете AI-ассистент для составления черновика аналитического отчёта о конкурентах. AI генерирует убедительный 5-страничный документ с долями рынка, данными о выручке конкурентов и прогнозами роста. На следующей неделе директор представит этот отчёт совету директоров. Что необходимо сделать ПЕРЕД подачей отчёта?',
    options = '[{"key": "A", "text_az": "Təqdim edin — AI alətləri etibarlı məlumatlar üzərində öyrədilib və rəqəmlər ağlabatan görünür", "text_en": "Submit it — AI tools are trained on reliable data and the numbers look reasonable", "text_ru": "Отправьте как есть — AI-инструменты обучены на достоверных данных, и цифры выглядят правдоподобно"}, {"key": "B", "text_az": "Hər faktiki iddianı ilkin mənbələrə (şirkət hesabatları, sənaye hesabatları, mətbuat buraxılışları) qarşı yoxlayın, AI-nin uydurmuş ola biləcəyi hər hansı məlumat nöqtəsini qeyd edin, və hər statistika üçün mənbə istinadları əlavə edin", "text_en": "Verify every factual claim against primary sources (company filings, industry reports, press releases), flag any data points the AI may have fabricated, and add source citations for each statistic", "text_ru": "Проверьте каждое фактическое утверждение по первичным источникам (корпоративная отчётность, отраслевые исследования, пресс-релизы), отметьте данные, которые AI мог выдумать, и добавьте ссылки на источники для каждой статистики"}, {"key": "C", "text_az": "Birinci AI-nin çıxışını yoxlamaq üçün başqa AI alətindən xahiş edin — AI alətləri arasında çarpaz yoxlama kifayətdir", "text_en": "Ask another AI tool to verify the first AI''s output — cross-checking between AI tools is sufficient", "text_ru": "Попросите другой AI-инструмент проверить результат первого — перекрёстная проверка между AI-инструментами является достаточной"}, {"key": "D", "text_az": "Hesabatın AI tərəfindən yaradıldığını və rəqəmlərin müstəqil yoxlanmalı olduğunu bildirən xəbərdarlıq əlavə edin", "text_en": "Add a disclaimer that the report was AI-generated and that numbers should be independently verified", "text_ru": "Добавьте оговорку о том, что отчёт создан с помощью AI и цифры требуют независимой проверки"}]'::jsonb
WHERE id = 'd0000006-0000-0000-0000-000000000014';

UPDATE public.questions SET
    scenario_ru = 'Вы обнаружили, что общая командная папка, содержащая 200 контактных записей клиентов, последние 2 недели была случайно открыта с доступом «Все, у кого есть ссылка, могут просматривать» вместо «Только для команды». Доказательств того, что кто-либо за пределами команды получал доступ, нет, однако подтвердить это невозможно. Ваша компания обрабатывает данные клиентов из ЕС. Какова ПРАВИЛЬНАЯ последовательность действий?',
    options = '[{"key": "A", "text_az": "İcazəni dərhal ''Yalnız komanda''ya dəyişdirin və davam edin — heç kim daxil olmayıb, zərər yoxdur", "text_en": "Change the permission to ''Team only'' immediately and move on — no one accessed it so no harm done", "text_ru": "Немедленно измените доступ на «Только для команды» и продолжайте работу — никто не заходил, значит, ущерба нет"}, {"key": "B", "text_az": "1) Dərhal girişi məhdudlaşdırın, 2) hər hansı xarici baxış üçün giriş qeydlərini yoxlayın, 3) hadisəni məlumatların müdafiəsi məmuruna və ya uyğunluq komandasına bildirin, 4) potensial GDPR bildiriş qiymətləndirməsi üçün zaman cədvəlini və əhatə dairəsini sənədləşdirin, 5) təkrarlanmanın qarşısını almaq üçün giriş nəzarəti tətbiq edin", "text_en": "1) Restrict access immediately, 2) check access logs for any external views, 3) report the incident to your data protection officer or compliance team, 4) document the timeline and scope for potential GDPR notification assessment, 5) implement access review controls to prevent recurrence", "text_ru": "1) Немедленно ограничьте доступ; 2) проверьте журналы доступа на наличие просмотров извне; 3) сообщите об инциденте ответственному за защиту данных или службе комплаенса; 4) задокументируйте хронологию и масштаб для оценки возможной необходимости уведомления по GDPR; 5) введите контроль прав доступа для предотвращения повторения"}, {"key": "C", "text_az": "İfşanın hər hansı izini silmək üçün qovluğu silin, sonra düzgün icazələrlə yenidən yaradın", "text_en": "Delete the folder to remove any trace of the exposure, then recreate it with correct permissions", "text_ru": "Удалите папку, чтобы устранить все следы утечки, а затем создайте её заново с корректными правами доступа"}, {"key": "D", "text_az": "Bütün 200 müştəriyə məlumatlarının ifşa oluna biləcəyini bildirin — şəffaflıq ən yaxşı siyasətdir", "text_en": "Notify all 200 clients that their data may have been exposed — transparency is the best policy", "text_ru": "Уведомите всех 200 клиентов о возможной утечке их данных — прозрачность является лучшей политикой"}]'::jsonb
WHERE id = 'd0000006-0000-0000-0000-000000000015';

UPDATE public.questions SET
    scenario_ru = 'Патрулируя зал мероприятия, вы замечаете посетителя, который сидит в одиночестве в углу: он явно дрожит и выглядит бледным. Каким будет ваш ПЕРВЫЙ шаг?',
    options = '[{"key": "A", "text_az": "Ona əhəmiyyət verməyin — onlar yəqin ki, sadəcə yorğundurlar.", "text_en": "Ignore it — they are probably just tired", "text_ru": "Не обращать внимания — скорее всего, он просто устал."}, {"key": "B", "text_az": "Təmkinlə yaxınlaşın, özünüzü təqdim edin və nəzakətlə onların yaxşı olub-olmadığını soruşun.", "text_en": "Approach calmly, introduce yourself, and gently ask if they are okay", "text_ru": "Спокойно подойти, представиться и мягко спросить, всё ли в порядке."}, {"key": "C", "text_az": "Səs gücləndirici sistem vasitəsilə bu şəxsi tanıyan kiminsə olub-olmadığı barədə elan edin.", "text_en": "Announce over the PA system asking if anyone knows this person", "text_ru": "Объявить по громкой связи, знает ли кто-нибудь этого человека."}, {"key": "D", "text_az": "Şəkli çəkib tədbir koordinatoruna göndərin.", "text_en": "Take a photo and send it to the event coordinator", "text_ru": "Сфотографировать и отправить снимок организатору мероприятия."}]'::jsonb
WHERE id = '80000001-0000-0000-0000-000000000001';

UPDATE public.questions SET
    scenario_ru = 'К вам на мероприятии подходит ребёнок примерно 8 лет и говорит, что не может найти родителей. Что вы делаете?',
    options = '[{"key": "A", "text_az": "Uşağa olduğu yerdə qalmağı tapşırın və köməyə birini göndərəcəksiniz.", "text_en": "Tell the child to stay where they are and you will send someone to help", "text_ru": "Попросить ребёнка оставаться на месте и пообещать прислать кого-нибудь на помощь."}, {"key": "B", "text_az": "Uşağın yanında qalın, onu təhlükəsiz, görünən bir yerə aparın, koordinatorunuza və təhlükəsizliyə məlumat verin, və uşağın adını və valideyn təsvirini soruşun.", "text_en": "Stay with the child, take them to a safe visible location, notify your coordinator and security, and ask the child''s name and parent description", "text_ru": "Остаться с ребёнком, отвести его на безопасное, хорошо просматриваемое место, сообщить координатору и службе охраны, а также узнать имя ребёнка и описание родителей."}, {"key": "C", "text_az": "Uşağa girişdə gözləməsini tapşırın və siz elan edəcəksiniz.", "text_en": "Ask the child to wait at the entrance and you will make an announcement", "text_ru": "Попросить ребёнка подождать у входа и сделать объявление."}, {"key": "D", "text_az": "Özünüz uşaqla birlikdə valideyni axtararaq məkanı gəzmək.", "text_en": "Walk the venue searching for the parent yourself with the child", "text_ru": "Самостоятельно обходить территорию вместе с ребёнком в поисках родителей."}]'::jsonb
WHERE id = '80000001-0000-0000-0000-000000000002';

UPDATE public.questions SET
    scenario_ru = 'Посетитель спрашивает, есть ли тихое место, где можно помолиться во время мероприятия. Вы не знаете ни о какой специально отведённой комнате для молитвы. Что вы делаете?',
    options = '[{"key": "A", "text_az": "Onlara belə bir otağın olmadığını və əvvəlcədən planlaşdırmalı olduqlarını bildirin.", "text_en": "Tell them there is no such room and they should have planned ahead", "text_ru": "Сообщить, что такой комнаты нет, и что следовало позаботиться об этом заранее."}, {"key": "B", "text_az": "Onların ehtiyaclarını hörmətlə nəzərə alın, koordinatorunuzdan mövcud hər hansı sakit məkanın olub-olmadığını dəqiqləşdirin və onları oraya müşayiət edin.", "text_en": "Acknowledge their need respectfully, check with your coordinator for any available quiet space, and escort them there", "text_ru": "С уважением отнестись к просьбе, уточнить у координатора, есть ли какое-либо тихое место, и проводить туда посетителя."}, {"key": "C", "text_az": "Onlara sanitar qovşağından istifadə etmələri tövsiyə olunur, çünki bu, ən sakit şəxsi məkandır.", "text_en": "Suggest they use the bathroom as it is the quietest private space", "text_ru": "Предложить воспользоваться туалетом — это самое тихое и уединённое место."}, {"key": "D", "text_az": "Sorğunu nəzərə almayın.", "text_en": "Ignore the request", "text_ru": "Оставить просьбу без внимания."}]'::jsonb
WHERE id = '80000001-0000-0000-0000-000000000003';

UPDATE public.questions SET
    scenario_ru = 'Во время мероприятия посетитель начинает делиться с вами глубоко личными и эмоционально тяжёлыми переживаниями. Как вы поступаете?',
    options = '[{"key": "A", "text_az": "Onların ehtiyac duyduğu qədər dinləmək.", "text_en": "Listen for as long as they need", "text_ru": "Слушать столько, сколько ему потребуется."}, {"key": "B", "text_az": "Qısaca empatiya ilə dinləyin, duyğularını qəbul edin, daha sonra nəzakətlə rolunuzun məhdudiyyətlərini izah edin və onları müvafiq dəstəyə yönəldin.", "text_en": "Listen briefly with empathy, acknowledge their feelings, then gently explain your role limits and guide them toward appropriate support", "text_ru": "Коротко выслушать с сочувствием, признать его чувства, а затем мягко объяснить границы своей роли и направить к соответствующей поддержке."}, {"key": "C", "text_az": "Nəzakətlə dərhal üzr istəyin — bu sizin işiniz deyil.", "text_en": "Politely excuse yourself immediately — this is not your job", "text_ru": "Вежливо сразу же извиниться и уйти — это не в вашей компетенции."}, {"key": "D", "text_az": "Onlara sizin şəxsi telefon nömrənizi verin ki, tədbirdən sonra sizə zəng edə bilsinlər.", "text_en": "Give them your personal phone number so they can call you after the event", "text_ru": "Дать свой личный номер телефона, чтобы он мог позвонить вам после мероприятия."}]'::jsonb
WHERE id = '80000001-0000-0000-0000-000000000004';

UPDATE public.questions SET
    scenario_ru = 'Молодой участник мероприятия (16 лет) тихонько говорит вам, что чувствует себя в опасности: взрослый, присутствующий на мероприятии, неоднократно прикасался к нему против его воли, и это причиняет ему дискомфорт. Что вы делаете?',
    options = '[{"key": "A", "text_az": "Onlara tədbirin qalan hissəsi ərzində həmin şəxsdən uzaq durmağı deyin.", "text_en": "Tell them to avoid that person for the rest of the event", "text_ru": "Посоветовать на оставшееся время мероприятия держаться подальше от этого человека."}, {"key": "B", "text_az": "Onlara inanın, sizə dedikləri üçün onlara təşəkkür edin, onların dərhal təhlükəsizliyini təmin edin, dərhal təyin olunmuş mühafizə üzrə məsul şəxsə məlumat verin və məxfiliyi vəd etməyin.", "text_en": "Believe them, thank them for telling you, ensure their immediate safety, report to the designated safeguarding officer immediately, and do not promise confidentiality", "text_ru": "Поверить ему, поблагодарить за то, что он рассказал вам, обеспечить его непосредственную безопасность, незамедлительно сообщить назначенному ответственному по защите детей и не обещать конфиденциальности."}, {"key": "C", "text_az": "Əvvəlcə təqsirləndirilən yetkin şəxsə özünüz yaxınlaşaraq araşdırın.", "text_en": "Investigate by approaching the accused adult yourself first", "text_ru": "Самостоятельно подойти к обвиняемому взрослому для выяснения обстоятельств."}, {"key": "D", "text_az": "Onlara bildirin ki, tədbir başa çatdıqdan sonra buna baxacaqsınız.", "text_en": "Tell them you will look into it after the event finishes", "text_ru": "Сообщить, что займётесь этим вопросом после окончания мероприятия."}]'::jsonb
WHERE id = '80000001-0000-0000-0000-000000000005';

UPDATE public.questions SET
    scenario_ru = 'Пожилой посетитель у стойки регистрации всё больше раздражается, не находя своего имени в списке. Он начинает повышать голос. Какой ответ будет наиболее эмпатичным и эффективным?',
    options = '[{"key": "A", "text_az": "Onların enerjisinə uyğunlaşın və ucadan, qətiyyətlə cavab verin.", "text_en": "Match their energy and speak loudly and firmly back", "text_ru": "Ответить в тон: громко и твёрдо."}, {"key": "B", "text_az": "Onların narazılığını anlayın, bilərəkdən səsinizi alçaldın, bunu həll edəcəyinizi təsdiqləyin, daha sonra sistemdə axtarış aparın və ehtiyac yaranarsa, əllə daxil etmə üçün müvəqqəti həll yolu təklif edin.", "text_en": "Acknowledge their frustration, lower your own voice deliberately, affirm you will resolve it, then search the system and offer a manual entry workaround if needed", "text_ru": "Признать его раздражение, намеренно понизить собственный голос, заверить, что вы решите проблему, проверить данные в системе и при необходимости предложить временное решение — внести вручную."}, {"key": "C", "text_az": "Dərhal təhlükəsizliyi çağırın.", "text_en": "Call security immediately", "text_ru": "Немедленно вызвать охрану."}, {"key": "D", "text_az": "Onlara kömək edə bilməzdən əvvəl sakitləşmələrini deyin.", "text_en": "Tell them to calm down before you can help them", "text_ru": "Сказать, что поможете, как только он успокоится."}]'::jsonb
WHERE id = '80000001-0000-0000-0000-000000000006';

UPDATE public.questions SET
    scenario_ru = 'Во время вашего семинара один из участников начинает плакать после группового упражнения, посвящённого личным сильным сторонам. Остальные участники выглядят смущёнными. Что вы делаете В ПЕРВУЮ ОЧЕРЕДЬ?',
    options = '[{"id": "a", "text": "Pause the session and ask the participant to step outside with you", "score": 0.9, "text_ru": "Прервать занятие и попросить участника выйти с вами."}, {"id": "b", "text": "Continue the exercise to avoid drawing more attention", "score": 0.2, "text_ru": "Продолжить упражнение, чтобы не привлекать лишнего внимания."}, {"id": "c", "text": "Ask the group to take a 5-minute break while you check in privately", "score": 1.0, "text_ru": "Попросить группу сделать перерыв на 5 минут и поговорить с участником наедине."}, {"id": "d", "text": "Tell the participant it is okay and move on quickly", "score": 0.4, "text_ru": "Сказать участнику, что всё в порядке, и быстро двигаться дальше."}]'::jsonb
WHERE id = 'e5000012-0000-4000-a000-000000000001';

UPDATE public.questions SET
    scenario_ru = 'Вы замечаете, что младший сотрудник на протяжении 2 недель необычно молчалив на совещаниях. Качество его работы не изменилось. Какой ответ будет НАИБОЛЕЕ эмпатичным?',
    options = '[{"id": "a", "text": "Raise it in the next team meeting so everyone can support them", "score": 0.1, "text_ru": "Поднять этот вопрос на следующем командном совещании, чтобы все могли поддержать его."}, {"id": "b", "text": "Send a private message: I noticed you seem quieter lately — is everything okay?", "score": 1.0, "text_ru": "Написать личное сообщение: «Я заметил, что в последнее время ты стал молчаливее — всё в порядке?»"}, {"id": "c", "text": "Wait until their work quality drops before intervening", "score": 0.2, "text_ru": "Подождать, пока качество его работы не ухудшится, и лишь тогда вмешаться."}, {"id": "d", "text": "Ask their manager to check on them", "score": 0.5, "text_ru": "Попросить его руководителя узнать, как у него дела."}]'::jsonb
WHERE id = 'e5000012-0000-4000-a000-000000000002';

UPDATE public.questions SET
    scenario_ru = 'На сессии обратной связи коллега говорит: «Мне кажется, никто не ценит мой вклад». Вы выступаете фасилитатором. Какой ответ будет НАИЛУЧШИМ?',
    options = '[{"id": "a", "text": "Acknowledge the feeling, then ask the group for specific examples of their contributions", "score": 1.0, "text_ru": "Признать это чувство, а затем попросить группу привести конкретные примеры его вклада."}, {"id": "b", "text": "Explain that everyone contributes equally", "score": 0.2, "text_ru": "Объяснить, что каждый вносит равный вклад."}, {"id": "c", "text": "Move on to avoid making the situation awkward", "score": 0.1, "text_ru": "Перейти к следующему пункту, чтобы не усугублять неловкую ситуацию."}, {"id": "d", "text": "Suggest they talk to HR about it", "score": 0.3, "text_ru": "Предложить ему поговорить об этом с отделом кадров."}]'::jsonb
WHERE id = 'e5000012-0000-4000-a000-000000000003';

UPDATE public.questions SET
    scenario_ru = 'За командным обедом вы замечаете, что обычно разговорчивый коллега уже несколько дней молчалив, отказался от двух социальных приглашений и явно рассеян на совещаниях. О каких-либо проблемах он не упоминал. Какой ответ будет НАИБОЛЕЕ уместным?',
    options = '[{"key": "A", "text_az": "Naharda başqalarının qarşısında birbaşa soruşun: ''Çox sakit olmusan — hər şey qaydasındadır?''", "text_en": "Ask them directly in front of others at lunch: ''You have been really quiet — is everything okay?''", "text_ru": "Спросить напрямую при всех за обедом: «Ты в последнее время очень тихий — всё хорошо?»"}, {"key": "B", "text_az": "Şəxsi bir an tapıb deyin: ''Son vaxtlar bir az fərqli göründüyünüzü hiss etdim. Paylaşmaq üçün heç bir təzyiq yoxdur, amma danışmaq istəsəniz burada olduğumu bilməyinizi istədim''", "text_en": "Find a private moment to say: ''I have noticed you seem a bit different lately. No pressure to share, but I wanted you to know I am here if you want to talk''", "text_ru": "Улучить момент наедине и сказать: «Я заметил, что в последнее время ты немного другой. Не хочу давить, но хотел, чтобы ты знал: если захочешь поговорить — я здесь.»"}, {"key": "C", "text_az": "Müşahidənizi HR-ə bildirin — onlar bu vəziyyətləri idarə etmək üçün hazırlıqlıdırlar", "text_en": "Report your observation to HR — they are trained to handle these situations", "text_ru": "Сообщить о своих наблюдениях в отдел кадров — они подготовлены для работы с такими ситуациями."}, {"key": "D", "text_az": "Onlara yer verin — hazır olduqlarında danışacaqlar", "text_en": "Give them space — they will talk when they are ready", "text_ru": "Дать ему пространство — когда будет готов, сам расскажет."}]'::jsonb
WHERE id = 'f0000008-0000-0000-0000-000000000011';

UPDATE public.questions SET
    scenario_ru = 'На командном мозговом штурме вы замечаете, что идеи коллеги из числа меньшинства раз за разом перебиваются или отклоняются другими участниками. Те же самые идеи, когда их спустя мгновение повторяет другой коллега, встречают живой отклик и поддержку. Какой ответ будет НАИБОЛЕЕ эффективным прямо сейчас?',
    options = '[{"key": "A", "text_az": "İclas zamanı heç nə deməyin, lakin sonra təsirlənmiş həmkarla şəxsi olaraq danışın", "text_en": "Say nothing during the meeting but speak to the affected colleague privately afterward", "text_ru": "Промолчать на совещании, но после поговорить с пострадавшим коллегой наедине."}, {"key": "B", "text_az": "İclasda deyərək krediti yönləndirin: ''Qeyd etmək istəyirəm ki, [həmkar] əslində bir neçə dəqiqə əvvəl eyni fikri irəli sürmüşdü — [həmkar], orijinal fikrinizi genişləndirə bilərsinizmi?''", "text_en": "In the meeting, redirect credit by saying: ''I want to highlight that [colleague] actually raised this same point a few minutes ago — [colleague], could you expand on your original idea?''", "text_ru": "На совещании перенаправить авторство: «Хочу обратить внимание: [коллега] высказал эту же идею несколько минут назад — [коллега], не могли бы вы развить свою первоначальную мысль?»"}, {"key": "C", "text_az": "Kəsən həmkarları birbaşa çağırın: ''Siz rədd edici davranırsınız və bu qəbuledilməzdir''", "text_en": "Call out the interrupting colleagues directly: ''You are being dismissive and that is not acceptable''", "text_ru": "Открыто указать тем, кто перебивает: «Вы ведёте себя пренебрежительно, и это недопустимо.»"}, {"key": "D", "text_az": "Buraxın — iclasda üzləşmək hər kəsi narahat edəcək", "text_en": "Let it go — confronting it in the meeting will make everyone uncomfortable", "text_ru": "Не вмешиваться — конфронтация на совещании создаст дискомфорт для всех."}]'::jsonb
WHERE id = 'f0000008-0000-0000-0000-000000000012';

UPDATE public.questions SET
    scenario_ru = 'Коллега доверительно сообщает вам, что переживает тяжёлый развод. В течение следующих двух недель он часто подходит к вашему рабочему месту, чтобы поговорить о своей ситуации, — порой на 30–40 минут. Ваша собственная работа начинает страдать. Вы искренне беспокоитесь о нём, но не можете продолжать быть его основной опорой. Какой ответ будет НАИБОЛЕЕ эмпатичным и профессиональным?',
    options = '[{"key": "A", "text_az": "Yaxınlaşdıqda məşğul görünməyə başlayın — çətin söhbət olmadan anlayacaqlar", "text_en": "Start looking busy when they approach — they will get the hint without a difficult conversation", "text_ru": "Начать выглядеть занятым, когда он подходит, — он сам поймёт намёк без трудного разговора."}, {"key": "B", "text_az": "Dürüst şəxsi söhbət edin: onlara əhəmiyyət verdiyinizi ifadə edin, keçirdiklərini etiraf edin, ehtiyac duyduqları dəstək səviyyəsini təmin etmək üçün təchiz olmadığınızı izah edin, və şirkətin işçi yardım proqramını və ya peşəkar məsləhətçini təklif edin", "text_en": "Have an honest private conversation: express that you care about them, acknowledge what they are going through, explain that you are not equipped to provide the level of support they need, and suggest the company''s employee assistance program or a professional counselor", "text_ru": "Поговорить с ним наедине откровенно: выразить заботу о нём, признать, через что он проходит, объяснить, что вы не в состоянии обеспечить тот уровень поддержки, который ему необходим, и предложить обратиться в программу помощи сотрудникам компании или к профессиональному психологу."}, {"key": "C", "text_az": "İşə diqqət yetirməli olduğunuzu söyləyin və əvəzinə HR ilə danışmağı təklif edin", "text_en": "Tell them you need to focus on work and suggest they talk to HR instead", "text_ru": "Сказать, что вам нужно сосредоточиться на работе, и предложить ему обратиться в отдел кадров."}, {"key": "D", "text_az": "Əlçatan olmağa davam edin — onların rifahı sizin son tarixlərinizdən daha vacibdir", "text_en": "Continue being available — their well-being is more important than your deadlines", "text_ru": "Продолжать быть доступным — его благополучие важнее ваших дедлайнов."}]'::jsonb
WHERE id = 'f0000008-0000-0000-0000-000000000013';

UPDATE public.questions SET
    scenario_ru = 'Во время корпоративного тренинга, который вы ведёте, участник в частном разговоре сообщает, что его руководитель делает высказывания, из-за которых тот чувствует себя небезопасно на работе. Участник просит никому об этом не говорить. Вы не являетесь его руководителем или представителем отдела кадров. Какой ответ будет ПРАВИЛЬНЫМ?',
    options = '[{"key": "A", "text_az": "Onların etibarını saxlayın — sizdən heç kimə deməməyinizi xahiş etdilər və arzularına hörmət etməlisiniz", "text_en": "Keep their confidence — they asked you not to tell anyone and you should respect their wishes", "text_ru": "Соблюдать конфиденциальность — он попросил никому не рассказывать, и нужно уважать его пожелание."}, {"key": "B", "text_az": "Etibar etdikləri üçün təşəkkür edin, birinin təhlükəsizliyi söz mövzusu olduqda tam gizlilik vəd edə bilməyəcəyinizə görə qayğı vəzifənizin olduğunu izah edin, onlara HR-ə və ya təyin olunmuş qoruma rəhbərinə müşayiət etməyi təklif edin, və açıqlanan məlumatı onların dəqiq sözlərindən istifadə edərək sənədləşdirin", "text_en": "Thank them for trusting you, explain that you have a duty of care and cannot promise full confidentiality when someone''s safety is involved, offer to accompany them to HR or the designated safeguarding lead, and document what was disclosed using their exact words", "text_ru": "Поблагодарить за доверие, объяснить, что у вас есть обязанность по заботе и вы не можете обещать полную конфиденциальность, когда речь идёт о чьей-либо безопасности, предложить сопроводить его в отдел кадров или к назначенному ответственному по защите, и зафиксировать сказанное его точными словами."}, {"key": "C", "text_az": "Vəziyyəti tez həll etmək üçün birbaşa menecerlə üzləşin", "text_en": "Confront the manager directly to resolve the situation quickly", "text_ru": "Напрямую поговорить с руководителем, чтобы быстро урегулировать ситуацию."}, {"key": "D", "text_az": "Onlara şərhləri sənədləşdirməyi və özlərinin HR-ə bildirməsini tövsiyə edin — bu onların məsuliyyətidir", "text_en": "Advise them to document the comments and report to HR themselves — it is their responsibility", "text_ru": "Посоветовать ему самому зафиксировать эти высказывания и сообщить в отдел кадров — это его ответственность."}]'::jsonb
WHERE id = 'f0000008-0000-0000-0000-000000000014';

UPDATE public.questions SET
    scenario_ru = 'Вы обнаруживаете, что старший коллега на протяжении последнего квартала передавал руководству поддельные показатели удовлетворённости клиентов. Завышенные цифры использовались для обоснования расширения команды и увеличения бюджета. Коллега пользуется уважением в коллективе, был вашим наставником, а в компании отсутствует официальный канал для информирования о нарушениях. Сообщение об этом может навредить вашей карьере. Что вы делаете?',
    options = '[{"key": "A", "text_az": "Həmkarla şəxsi olaraq üzləşin və rəqəmləri özlərinin düzəltmələri üçün şans verin", "text_en": "Confront the colleague privately and give them a chance to correct the numbers themselves", "text_ru": "Поговорить с коллегой наедине и дать ему возможность самостоятельно исправить показатели."}, {"key": "B", "text_az": "Sübutları hərtərəfli sənədləşdirin, ən uyğun bildirmə yolunu müəyyənləşdirin (etika komitəsi, hüquq və ya həmkarın zəncirindən kənar etibarlı böyük rəhbər), sənədləşdirilmiş sübutlarla bildirin, və zaman cədvəlinin şəxsi qeydini saxlayın", "text_en": "Document the evidence thoroughly, identify the most appropriate reporting path (ethics committee, legal, or a trusted senior leader outside the colleague''s chain), report with the documented evidence, and keep a personal record of the timeline", "text_ru": "Тщательно задокументировать доказательства, определить наиболее подходящий канал для обращения (комитет по этике, юридический отдел или авторитетный руководитель за пределами подчинённости коллеги), сообщить о нарушении с задокументированными доказательствами и сохранить личную запись хронологии событий."}, {"key": "C", "text_az": "Real rəqəmləri anonim olaraq rəhbərliyə sızdırın və araşdırmalarına icazə verin", "text_en": "Anonymously leak the real numbers to leadership and let them investigate", "text_ru": "Анонимно передать реальные цифры руководству и позволить ему провести расследование."}, {"key": "D", "text_az": "Susun — şişirdilmiş rəqəmlər bütün komandaya fayda verir və onları ifşa etmək siz daxil olmaqla hər kəsə zərər verəcək", "text_en": "Stay quiet — the inflated numbers benefit the whole team and exposing them will hurt everyone, including yourself", "text_ru": "Промолчать — завышенные показатели идут на пользу всей команде, и их разоблачение ударит по всем, включая вас."}]'::jsonb
WHERE id = 'f0000008-0000-0000-0000-000000000015';

UPDATE public.questions SET
    scenario_ru = 'Делегат спрашивает: "Where is the registration desk?" Какой ответ наиболее уместен?',
