UPDATE public.questions SET
    scenario_ru = 'Спортсмен спрашивает: "Is there a gym nearby we can use?" Вы не уверены. Что вы скажете?',
    options = '[{"key": "A", "text_az": "Bəli, yaxınlıqda biri mövcuddur, əmin olmasam da.", "text_en": "Yes there is one nearby — even though unsure", "text_ru": "Yes there is one nearby — even though unsure"}, {"key": "B", "text_az": "Sualı nəzərə almayın.", "text_en": "Ignore the question", "text_ru": "Ignore the question"}, {"key": "C", "text_az": "Bu, həqiqətən də əla bir sualdır. Lakin dəqiq məlumatım yoxdur, icazə verin sizin üçün dərhal öyrənim.", "text_en": "That is a great question — I am not certain but let me find out for you right now", "text_ru": "That is a great question — I am not certain but let me find out for you right now"}, {"key": "D", "text_az": "Bilmirəm və bununla kifayətlənirəm.", "text_en": "I do not know — and leave it at that", "text_ru": "I do not know — and leave it at that"}]'::jsonb
