UPDATE public.questions SET
    scenario_ru = 'На приёме партнёр спрашивает об использовании возобновляемых источников энергии в Азербайджане. Эта тема выходит за рамки ваших тезисов. Как вы ответите?',
    options = '[{"key": "A", "text_az": "Bilikli görünmək üçün faktlar uydurun.", "text_en": "Make up facts to seem knowledgeable", "text_ru": "Make up facts to seem knowledgeable"}, {"key": "B", "text_az": "Həqiqətən bildiklərinizi bölüşün və onları bir mütəxəssislə əlaqələndirməyi təklif edin.", "text_en": "Share what you genuinely know and offer to connect them with a specialist", "text_ru": "Share what you genuinely know and offer to connect them with a specialist"}, {"key": "C", "text_az": "Bu barədə heç nə bilmirəm — söhbətə son qoyulur.", "text_en": "I do not know anything about that — end conversation", "text_ru": "I do not know anything about that — end conversation"}, {"key": "D", "text_az": "Dərhal mövzunu dəyişdirin.", "text_en": "Change the subject immediately", "text_ru": "Change the subject immediately"}]'::jsonb
